</p>\r\n        <p style=\\\"margin:0;color:rgba(255,255,255,0.8);font-size:.88rem;line-height:1.65;\\\">\r\n          &lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;{{ app.request.locale }}&quot; {% if app.request.locale == &#039;ar&#039; %}dir=&quot;rtl&quot;{% endif %}&gt;\n&lt;head&gt;\n  &lt;meta charset=&quot;UTF-8&quot;&gt;\n  &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;\n  &lt;title&gt;{% block title %}SmartTrip{% endblock %}&lt;/title&gt;\n  &lt;link href=&quot;https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&amp;family=Plus+Jakarta+Sans:wght@300;400;500;600;700&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;\n  &lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css&quot;&gt;\n  &lt;style&gt;\n    :root {\n      --navy:   #0d1b2a;\n      --navy-2: #112236;\n      --gold:   #c9a84c;\n      --gold-l: #e8c97a;\n      --cream:  #f5f0e8;\n      --white:  #ffffff;\n      --muted:  #7a8a99;\n      --shadow: 0 8px 32px rgba(13,27,42,0.18);\n    }\n    * { margin:0; padding:0; box-sizing:border-box; }\n    html { scroll-behavior:smooth; }\n    body { font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; background:var(--cream); color:var(--navy); overflow-x:hidden; }\n\n    {% if app.request.locale == &#039;ar&#039; %}\n    body { font-family: &#039;Segoe UI&#039;, &#039;Arial&#039;, sans-serif; direction: rtl; }\n    {% endif %}\n\n    /* ── NAV ── */\n    nav {\n      position:fixed; top:0; width:100%; z-index:1000;\n      display:flex; align-items:center; justify-content:space-between;\n      padding:1.1rem 5%;\n      background:rgba(13,27,42,0.96);\n      backdrop-filter:blur(20px);\n      border-bottom:1px solid rgba(201,168,76,0.2);\n      transition:all .3s;\n    }\n    .nav-logo { font-family:&#039;Playfair Display&#039;,serif; font-size:1.5rem; font-weight:700; color:var(--gold); text-decoration:none; letter-spacing:1px; }\n    .nav-logo span { color:var(--white); }\n    .nav-links { display:flex; gap:2rem; list-style:none; align-items:center; }\n    .nav-links a { color:rgba(255,255,255,0.7); text-decoration:none; font-size:.875rem; font-weight:500; transition:color .3s; position:relative; }\n    .nav-links a::after { content:&#039;&#039;; position:absolute; bottom:-4px; left:0; width:0; height:1px; background:var(--gold); transition:width .3s; }\n    .nav-links a:hover { color:var(--gold); }\n    .nav-links a:hover::after { width:100%; }\n    .nav-cta { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy) !important; padding:.55rem 1.4rem; border-radius:50px; font-weight:700 !important; }\n    .nav-cta::after { display:none !important; }\n\n    /* ── LANGUAGE SWITCHER ── */\n    .lang-switcher {\n      display:flex; align-items:center; gap:.3rem;\n      background:rgba(255,255,255,0.05);\n      border:1px solid rgba(201,168,76,0.2);\n      border-radius:50px;\n      padding:.3rem .5rem;\n    }\n    .lang-btn {\n      background:none; border:none; cursor:pointer;\n      color:rgba(255,255,255,0.45);\n      font-size:.72rem; font-weight:700;\n      padding:.25rem .5rem;\n      border-radius:50px;\n      transition:all .2s;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      letter-spacing:.5px;\n      text-decoration:none;\n      display:inline-flex; align-items:center; gap:.25rem;\n    }\n    .lang-btn:hover { color:var(--gold); background:rgba(201,168,76,0.1); }\n    .lang-btn.active { background:var(--gold); color:var(--navy); }\n    .lang-divider { color:rgba(255,255,255,0.15); font-size:.7rem; }\n\n    /* ── BOUTON LOGIN NAVBAR ── */\n    .btn-login-nav {\n      display:inline-flex; align-items:center; gap:.4rem;\n      padding:.5rem 1.1rem;\n      border:1px solid rgba(201,168,76,0.4);\n      border-radius:50px;\n      color:rgba(255,255,255,0.75) !important;\n      font-size:.8rem; font-weight:600;\n      cursor:pointer; transition:all .25s;\n      background:transparent;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      text-decoration:none;\n    }\n    .btn-login-nav::after { display:none !important; }\n    .btn-login-nav:hover { border-color:var(--gold); color:var(--gold) !important; background:rgba(201,168,76,0.08); }\n    .btn-login-nav i { font-size:.75rem; color:var(--gold); }\n\n    /* Badge user connecté */\n    .nav-user {\n      display:inline-flex; align-items:center; gap:.5rem;\n      padding:.45rem 1rem;\n      background:rgba(201,168,76,0.12);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:50px;\n      font-size:.78rem; color:var(--gold); font-weight:600;\n    }\n    .nav-user i { font-size:.75rem; }\n\n    /* ── MODAL LOGIN ── */\n    .modal-overlay {\n      display:none;\n      position:fixed; inset:0; z-index:9999;\n      background:rgba(7,16,26,0.85);\n      backdrop-filter:blur(8px);\n      align-items:center; justify-content:center;\n    }\n    .modal-overlay.open { display:flex; }\n    .modal-card {\n      background:rgba(17,34,54,0.98);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:20px;\n      padding:2.5rem 2.2rem;\n      width:100%; max-width:400px;\n      position:relative;\n      animation:modalIn .25s ease;\n    }\n    @keyframes modalIn {\n      from { opacity:0; transform:translateY(-20px) scale(0.97); }\n      to   { opacity:1; transform:translateY(0)     scale(1);    }\n    }\n    .modal-close {\n      position:absolute; top:1rem; right:1.1rem;\n      background:none; border:none; color:rgba(255,255,255,0.35);\n      font-size:1.2rem; cursor:pointer; transition:color .2s; line-height:1;\n    }\n    .modal-close:hover { color:var(--gold); }\n    .modal-logo { text-align:center; margin-bottom:1.6rem; }\n    .modal-logo h2 { font-family:&#039;Playfair Display&#039;,serif; font-size:1.6rem; font-weight:700; color:var(--gold); }\n    .modal-logo h2 span { color:var(--white); }\n    .modal-logo p { font-size:.75rem; color:rgba(255,255,255,0.35); margin-top:.3rem; }\n    .modal-field { margin-bottom:1.1rem; }\n    .modal-field label { display:block; font-size:.68rem; font-weight:700; letter-spacing:.12em; text-transform:uppercase; color:rgba(255,255,255,0.45); margin-bottom:.45rem; }\n    .modal-field input { width:100%; padding:.8rem 1rem; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.2); border-radius:10px; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .modal-field input:focus { border-color:var(--gold); }\n    .modal-field input::placeholder { color:rgba(255,255,255,0.2); }\n    .modal-remember { display:flex; align-items:center; gap:.5rem; margin-bottom:1.4rem; }\n    .modal-remember input[type=&quot;checkbox&quot;] { accent-color:var(--gold); }\n    .modal-remember label { font-size:.75rem; color:rgba(255,255,255,0.4); }\n    .btn-modal-submit { width:100%; padding:.9rem; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; border-radius:10px; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.9rem; font-weight:700; cursor:pointer; transition:transform .3s,box-shadow .3s; letter-spacing:.03em; }\n    .btn-modal-submit:hover { transform:translateY(-2px); box-shadow:0 10px 28px rgba(201,168,76,0.4); }\n    .modal-error { background:rgba(248,113,113,.1); border:1px solid rgba(248,113,113,.3); border-radius:8px; padding:.75rem 1rem; color:#fca5a5; font-size:.8rem; margin-bottom:1.1rem; text-align:center; }\n\n    /* ── FLASH ── */\n    .flash { padding:1rem 5%; margin-top:72px; font-size:.875rem; }\n    .flash-success { background:rgba(74,222,128,.1); border-left:3px solid #4ade80; color:#166534; }\n    .flash-error   { background:rgba(248,113,113,.1); border-left:3px solid #f87171; color:#991b1b; }\n\n    /* ── HERO ── */\n    .hero { min-height:100vh; position:relative; display:flex; align-items:center; overflow:hidden; }\n    .hero-bg { position:absolute; inset:0; background:url(&#039;https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1920&amp;q=80&#039;) center/cover no-repeat; }\n    .hero-overlay { position:absolute; inset:0; background:linear-gradient(135deg,rgba(13,27,42,0.95) 0%,rgba(13,27,42,0.65) 50%,rgba(13,27,42,0.4) 100%); }\n    .hero-content { position:relative; z-index:2; padding:0 5%; max-width:720px; }\n    .hero-badge { display:inline-flex; align-items:center; gap:.5rem; background:rgba(201,168,76,0.15); border:1px solid rgba(201,168,76,0.35); color:var(--gold); padding:.4rem 1rem; border-radius:50px; font-size:.75rem; font-weight:600; letter-spacing:1.5px; text-transform:uppercase; margin-bottom:1.5rem; }\n    .hero h1 { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(2.5rem,6vw,5rem); line-height:1.1; margin-bottom:1.5rem; color:var(--white); }\n    .hero h1 em { font-style:italic; color:var(--gold); }\n    .hero p { font-size:1.05rem; color:rgba(255,255,255,0.7); line-height:1.75; margin-bottom:2.5rem; max-width:500px; }\n    .hero-btns { display:flex; gap:1rem; flex-wrap:wrap; }\n    .hero-search { position:absolute; bottom:2.5rem; left:5%; right:5%; z-index:2; }\n    .search-box { background:rgba(13,27,42,0.92); border:1px solid rgba(201,168,76,0.25); border-radius:16px; padding:1.4rem 2rem; display:flex; gap:1rem; align-items:center; flex-wrap:wrap; backdrop-filter:blur(20px); }\n    .search-field { flex:1; min-width:140px; display:flex; flex-direction:column; gap:.25rem; }\n    .search-field label { font-size:.65rem; text-transform:uppercase; letter-spacing:1.2px; color:var(--gold); font-weight:700; }\n    .search-field input, .search-field select { background:transparent; border:none; outline:none; color:var(--white); font-size:.9rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; cursor:pointer; }\n    .search-field select option { background:var(--navy); }\n    .search-divider { width:1px; height:36px; background:rgba(201,168,76,0.2); }\n    .search-btn { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.85rem 1.6rem; border-radius:10px; font-weight:700; font-size:.875rem; display:flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; white-space:nowrap; }\n    .search-btn:hover { transform:translateY(-2px); box-shadow:0 8px 25px rgba(201,168,76,0.4); }\n\n    /* ── BUTTONS ── */\n    .btn-primary { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); padding:.85rem 2rem; border-radius:50px; font-weight:700; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-primary:hover { transform:translateY(-3px); box-shadow:0 12px 35px rgba(201,168,76,0.4); }\n    .btn-outline-light { border:1px solid rgba(255,255,255,0.35); color:var(--white); padding:.85rem 2rem; border-radius:50px; font-weight:500; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; backdrop-filter:blur(10px); transition:border-color .3s,background .3s; cursor:pointer; }\n    .btn-outline-light:hover { border-color:var(--gold); background:rgba(201,168,76,0.1); color:var(--gold); }\n    .btn-gold { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.6rem 1.4rem; border-radius:50px; font-weight:700; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:transform .3s,box-shadow .3s; }\n    .btn-gold:hover { transform:translateY(-2px); box-shadow:0 8px 20px rgba(201,168,76,0.4); }\n    .btn-navy { background:var(--navy); color:var(--gold); border:1px solid rgba(201,168,76,0.3); padding:.6rem 1.4rem; border-radius:50px; font-weight:600; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:all .3s; }\n    .btn-navy:hover { background:var(--gold); color:var(--navy); }\n    .btn-danger-sm { background:rgba(220,38,38,0.1); color:#dc2626; border:1px solid rgba(220,38,38,0.2); padding:.4rem .9rem; border-radius:8px; cursor:pointer; font-size:.78rem; font-weight:600; text-decoration:none; display:inline-flex; align-items:center; gap:.3rem; transition:all .3s; }\n    .btn-danger-sm:hover { background:rgba(220,38,38,0.2); }\n\n    /* ── SECTIONS ── */\n    section { padding:5rem 5%; }\n    .section-label { display:inline-block; color:var(--gold); font-size:.72rem; font-weight:700; letter-spacing:2.5px; text-transform:uppercase; margin-bottom:.75rem; }\n    .section-title { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(1.8rem,3.5vw,2.8rem); color:var(--navy); line-height:1.2; margin-bottom:.75rem; }\n    .section-title.light { color:var(--white); }\n    .section-sub { color:var(--muted); font-size:.95rem; line-height:1.75; max-width:480px; }\n    .section-header { display:flex; justify-content:space-between; align-items:flex-end; margin-bottom:2.5rem; flex-wrap:wrap; gap:1rem; }\n\n    /* ── DESTINATIONS GRID ── */\n    #destinations { background:var(--cream); }\n    .dest-grid { display:grid; grid-template-columns:repeat(3,1fr); grid-template-rows:auto auto; gap:1.2rem; }\n    .dest-card { position:relative; border-radius:14px; overflow:hidden; cursor:pointer; }\n    .dest-card-featured { grid-row:1/3; }\n    .dest-card img { width:100%; height:100%; min-height:220px; object-fit:cover; transition:transform .6s; }\n    .dest-card-featured img { min-height:480px; }\n    .dest-card:hover img { transform:scale(1.07); }\n    .dest-overlay { position:absolute; inset:0; background:linear-gradient(to top,rgba(13,27,42,0.92) 0%,transparent 55%); display:flex; flex-direction:column; justify-content:flex-end; padding:1.6rem; }\n    .dest-badge { background:rgba(201,168,76,0.92); color:var(--navy); font-size:.65rem; font-weight:700; padding:.2rem .6rem; border-radius:50px; display:inline-block; margin-bottom:.6rem; width:fit-content; letter-spacing:.5px; text-transform:uppercase; }\n    .dest-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.3rem; color:var(--white); margin-bottom:.25rem; }\n    .dest-card-featured .dest-name { font-size:1.7rem; }\n    .dest-info { display:flex; justify-content:space-between; align-items:center; }\n    .dest-price { color:var(--gold); font-weight:700; font-size:.95rem; }\n    .dest-action { width:34px; height:34px; background:var(--gold); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--navy); font-size:.75rem; opacity:0; transform:translateY(8px); transition:opacity .3s,transform .3s; text-decoration:none; }\n    .dest-card:hover .dest-action { opacity:1; transform:translateY(0); }\n\n    /* ── PACKAGES ── */\n    #packages { background:var(--navy); }\n    .packages-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:1.4rem; margin-top:2.5rem; }\n    .pkg-card { background:var(--navy-2); border:1px solid rgba(201,168,76,0.12); border-radius:14px; overflow:hidden; transition:transform .3s,box-shadow .3s,border-color .3s; position:relative; }\n    .pkg-card:hover { transform:translateY(-8px); box-shadow:0 25px 60px rgba(0,0,0,0.4); border-color:rgba(201,168,76,0.35); }\n    .pkg-card.featured { border-color:var(--gold); }\n    .pkg-ribbon { position:absolute; top:1rem; right:1rem; background:var(--gold); color:var(--navy); font-size:.65rem; font-weight:700; padding:.25rem .75rem; border-radius:50px; z-index:1; letter-spacing:.5px; }\n    .pkg-img { height:190px; overflow:hidden; }\n    .pkg-img img { width:100%; height:100%; object-fit:cover; transition:transform .5s; }\n    .pkg-card:hover .pkg-img img { transform:scale(1.08); }\n    .pkg-body { padding:1.4rem; }\n    .pkg-meta { display:flex; gap:.8rem; font-size:.75rem; color:rgba(255,255,255,0.5); margin-bottom:.9rem; flex-wrap:wrap; }\n    .pkg-meta span { display:flex; align-items:center; gap:.3rem; }\n    .pkg-meta i { color:var(--gold); }\n    .pkg-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.15rem; color:var(--white); margin-bottom:.4rem; }\n    .pkg-desc { color:rgba(255,255,255,0.55); font-size:.82rem; line-height:1.65; margin-bottom:1.1rem; }\n    .pkg-features { list-style:none; margin-bottom:1.3rem; }\n    .pkg-features li { font-size:.8rem; color:rgba(255,255,255,0.6); display:flex; align-items:center; gap:.45rem; padding:.25rem 0; }\n    .pkg-features i { color:var(--gold); font-size:.65rem; }\n    .pkg-footer { display:flex; justify-content:space-between; align-items:center; border-top:1px solid rgba(201,168,76,0.12); padding-top:1.1rem; }\n    .pkg-price-label { font-size:.7rem; color:rgba(255,255,255,0.45); }\n    .pkg-price { font-size:1.4rem; font-weight:700; color:var(--gold); }\n    .pkg-price small { font-size:.7rem; color:rgba(255,255,255,0.45); }\n\n    /* ── ABOUT ── */\n    #about { background:var(--cream); display:grid; grid-template-columns:1fr 1fr; gap:5rem; align-items:center; }\n    .about-img-wrap { position:relative; }\n    .about-img-main { width:100%; height:480px; object-fit:cover; border-radius:16px; }\n    .about-img-badge { position:absolute; bottom:-1.5rem; right:-1.5rem; background:var(--gold); color:var(--navy); border-radius:14px; padding:1.4rem; text-align:center; box-shadow:0 20px 50px rgba(201,168,76,0.3); }\n    .about-img-badge strong { font-size:2.2rem; display:block; line-height:1; font-family:&#039;Playfair Display&#039;,serif; }\n    .about-img-badge span { font-size:.75rem; font-weight:600; letter-spacing:.5px; }\n    .about-features { display:grid; grid-template-columns:1fr 1fr; gap:1rem; margin:1.8rem 0; }\n    .about-feat { display:flex; gap:.9rem; align-items:flex-start; background:var(--white); border:1px solid rgba(201,168,76,0.12); padding:1.1rem; border-radius:12px; transition:border-color .3s,box-shadow .3s; }\n    .about-feat:hover { border-color:var(--gold); box-shadow:var(--shadow); }\n    .about-feat-icon { width:40px; height:40px; background:rgba(201,168,76,0.1); border-radius:10px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .about-feat h4 { font-size:.875rem; color:var(--navy); margin-bottom:.25rem; font-weight:600; }\n    .about-feat p { font-size:.78rem; color:var(--muted); line-height:1.5; }\n\n    /* ── CONTACT ── */\n    #contact { background:var(--navy); display:grid; grid-template-columns:1fr 1.5fr; gap:5rem; align-items:start; }\n    .contact-items { display:flex; flex-direction:column; gap:1.4rem; margin-top:2rem; }\n    .contact-item { display:flex; gap:1rem; align-items:flex-start; }\n    .contact-icon { width:46px; height:46px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:12px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .contact-item h4 { font-size:.78rem; color:rgba(255,255,255,0.5); margin-bottom:.2rem; text-transform:uppercase; letter-spacing:.5px; }\n    .contact-item p { color:var(--white); font-size:.9rem; }\n    .contact-form { background:rgba(255,255,255,0.04); border:1px solid rgba(201,168,76,0.15); border-radius:18px; padding:2.2rem; }\n    .contact-form h3 { font-family:&#039;Playfair Display&#039;,serif; margin-bottom:1.4rem; color:var(--white); font-size:1.3rem; }\n    .form-row { display:grid; grid-template-columns:1fr 1fr; gap:1rem; }\n    .form-group { margin-bottom:1.1rem; }\n    .form-group label { display:block; font-size:.72rem; color:rgba(255,255,255,0.55); font-weight:600; letter-spacing:.5px; text-transform:uppercase; margin-bottom:.45rem; }\n    .form-group input, .form-group select, .form-group textarea { width:100%; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.15); border-radius:10px; padding:.75rem 1rem; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color:var(--gold); }\n    .form-group textarea { resize:vertical; min-height:100px; }\n    .form-group select option { background:var(--navy); }\n    .btn-submit { width:100%; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.95rem; border-radius:10px; font-weight:700; font-size:.95rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; display:flex; align-items:center; justify-content:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-submit:hover { transform:translateY(-2px); box-shadow:0 12px 30px rgba(201,168,76,0.4); }\n\n    /* ── FOOTER ── */\n    footer { background:#07101a; border-top:1px solid rgba(201,168,76,0.1); padding:3.5rem 5% 2rem; }\n    .footer-grid { display:grid; grid-template-columns:1.5fr 1fr 1fr 1fr; gap:3rem; margin-bottom:2.5rem; }\n    .footer-brand p { color:rgba(255,255,255,0.45); font-size:.82rem; line-height:1.7; margin:1rem 0 1.3rem; }\n    .social-links { display:flex; gap:.7rem; }\n    .social-link { width:36px; height:36px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--gold); font-size:.8rem; text-decoration:none; transition:background .3s,transform .3s; }\n    .social-link:hover { background:var(--gold); color:var(--navy); transform:translateY(-3px); }\n    .footer-col h4 { font-size:.82rem; font-weight:700; color:var(--white); margin-bottom:1rem; letter-spacing:.5px; text-transform:uppercase; }\n    .footer-col ul { list-style:none; }\n    .footer-col ul li { margin-bottom:.55rem; }\n    .footer-col ul a { color:rgba(255,255,255,0.45); text-decoration:none; font-size:.82rem; transition:color .3s; display:flex; align-items:center; gap:.35rem; }\n    .footer-col ul a:hover { color:var(--gold); }\n    .footer-bottom { border-top:1px solid rgba(201,168,76,0.1); padding-top:1.4rem; display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:1rem; }\n    .footer-bottom p { color:rgba(255,255,255,0.35); font-size:.78rem; }\n    .footer-bottom span { color:var(--gold); }\n\n    /* ── RESPONSIVE ── */\n    @media(max-width:1024px) {\n      .dest-grid { grid-template-columns:1fr 1fr; }\n      .dest-card-featured { grid-row:auto; }\n      .packages-grid { grid-template-columns:1fr 1fr; }\n      #about,#contact { grid-template-columns:1fr; gap:3rem; }\n      .footer-grid { grid-template-columns:1fr 1fr; }\n    }\n    @media(max-width:768px) {\n      .nav-links { display:none; }\n      .dest-grid,.packages-grid { grid-template-columns:1fr; }\n      .search-box { flex-direction:column; }\n      .search-divider { display:none; }\n      .about-features,.form-row { grid-template-columns:1fr; }\n      .footer-grid { grid-template-columns:1fr; gap:2rem; }\n      .about-img-badge { right:1rem; bottom:1rem; }\n      #chat-widget { bottom:16px !important; right:16px !important; }\n      #chat-popup  { width:calc(100vw - 32px) !important; }\n    }\n\n    @keyframes fadeInUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }\n    .fade-in  { animation:fadeInUp .8s ease forwards; }\n    .delay-1  { animation-delay:.2s; opacity:0; }\n    .delay-2  { animation-delay:.4s; opacity:0; }\n\n    {% block extra_css %}{% endblock %}\n  &lt;/style&gt;\n  {% block stylesheets %}{% endblock %}\n&lt;/head&gt;\n&lt;body&gt;\n\n{# ══ MODAL LOGIN ══════════════════════════════════════════════════ #}\n{% if not app.user %}\n&lt;div class=&quot;modal-overlay&quot; id=&quot;loginModal&quot;&gt;\n  &lt;div class=&quot;modal-card&quot;&gt;\n    &lt;button class=&quot;modal-close&quot; onclick=&quot;closeModal()&quot; title=&quot;Fermer&quot;&gt;✕&lt;/button&gt;\n    &lt;div class=&quot;modal-logo&quot;&gt;\n      &lt;h2&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/h2&gt;\n      &lt;p&gt;{{ &#039;login.title&#039;|trans }}&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;div style=&quot;display:flex; gap:.5rem; margin-bottom:1.5rem;&quot;&gt;\n      &lt;button onclick=&quot;switchTab(&#039;password&#039;)&quot; id=&quot;tab-password&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:700;\n               background:linear-gradient(135deg,var(--gold),var(--gold-l));\n               color:var(--navy); border:1px solid var(--gold); transition:all .3s;&quot;&gt;\n        🔑 {{ &#039;login.password_tab&#039;|trans }}\n      &lt;/button&gt;\n      &lt;button onclick=&quot;switchTab(&#039;faceid&#039;)&quot; id=&quot;tab-faceid&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:600;\n               background:transparent; color:rgba(255,255,255,0.6);\n               border:1px solid rgba(201,168,76,0.3); transition:all .3s;&quot;&gt;\n        📷 {{ &#039;login.faceid_tab&#039;|trans }}\n      &lt;/button&gt;\n    &lt;/div&gt;\n    {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n      &lt;div class=&quot;modal-error&quot;&gt;❌ {{ error.messageKey|trans(error.messageData, &#039;security&#039;) }}&lt;/div&gt;\n    {% endif %}\n    &lt;div id=&quot;panel-password&quot;&gt;\n      &lt;form method=&quot;POST&quot; action=&quot;{{ path(&#039;app_login&#039;) }}&quot;&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_email&quot;&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;email&quot; id=&quot;modal_email&quot; name=&quot;email&quot; value=&quot;{{ last_username ?? &#039;&#039; }}&quot; placeholder=&quot;votre@email.com&quot; autocomplete=&quot;email&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_password&quot;&gt;{{ &#039;login.password&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;password&quot; id=&quot;modal_password&quot; name=&quot;password&quot; placeholder=&quot;••••••••&quot; autocomplete=&quot;current-password&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-remember&quot;&gt;\n          &lt;input type=&quot;checkbox&quot; id=&quot;modal_remember&quot; name=&quot;_remember_me&quot;&gt;\n          &lt;label for=&quot;modal_remember&quot;&gt;{{ &#039;login.remember&#039;|trans }}&lt;/label&gt;\n        &lt;/div&gt;\n        &lt;input type=&quot;hidden&quot; name=&quot;_csrf_token&quot; value=&quot;{{ csrf_token(&#039;authenticate&#039;) }}&quot;&gt;\n        &lt;button type=&quot;submit&quot; class=&quot;btn-modal-submit&quot;&gt;\n          &lt;i class=&quot;fas fa-sign-in-alt&quot;&gt;&lt;/i&gt; {{ &#039;login.submit&#039;|trans }}\n        &lt;/button&gt;\n      &lt;/form&gt;\n    &lt;/div&gt;\n    &lt;div id=&quot;panel-faceid&quot; style=&quot;display:none;&quot;&gt;\n      &lt;div class=&quot;modal-field&quot;&gt;\n        &lt;label&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n        &lt;input type=&quot;email&quot; id=&quot;faceEmail&quot; placeholder=&quot;votre@email.com&quot; style=&quot;width:100%;padding:.8rem 1rem;background:rgba(255,255,255,0.06);border:1px solid rgba(201,168,76,0.2);border-radius:10px;color:var(--white);font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;font-size:.875rem;outline:none;&quot;&gt;\n      &lt;/div&gt;\n      &lt;div style=&quot;position:relative;border-radius:12px;overflow:hidden;border:1px solid rgba(201,168,76,0.3);margin-bottom:1rem;background:#000;&quot;&gt;\n        &lt;video id=&quot;webcam&quot; autoplay playsinline style=&quot;width:100%;height:200px;display:block;object-fit:cover;&quot;&gt;&lt;/video&gt;\n        &lt;canvas id=&quot;canvas&quot; width=&quot;320&quot; height=&quot;240&quot; style=&quot;display:none;&quot;&gt;&lt;/canvas&gt;\n        &lt;div style=&quot;position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none;&quot;&gt;\n          &lt;div style=&quot;width:110px;height:135px;border:2px solid var(--gold);border-radius:55px;opacity:.7;box-shadow:0 0 20px rgba(201,168,76,0.3);&quot;&gt;&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div style=&quot;position:absolute;bottom:.5rem;left:0;right:0;text-align:center;font-size:.7rem;color:rgba(255,255,255,0.5);&quot;&gt;\n          {{ &#039;login.face_center&#039;|trans }}\n        &lt;/div&gt;\n      &lt;/div&gt;\n      &lt;button id=&quot;faceLoginBtn&quot; class=&quot;btn-modal-submit&quot; type=&quot;button&quot;&gt;\n        &lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; {{ &#039;login.face_scan&#039;|trans }}\n      &lt;/button&gt;\n      &lt;p id=&quot;faceResult&quot; style=&quot;text-align:center;margin-top:.75rem;font-size:.82rem;min-height:1.2rem;color:rgba(255,255,255,0.6);&quot;&gt;&lt;/p&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/div&gt;\n{% endif %}\n\n{# ══ NAVBAR ══════════════════════════════════════════════════════ #}\n&lt;nav id=&quot;navbar&quot;&gt;\n  &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot;&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/a&gt;\n  &lt;ul class=&quot;nav-links&quot;&gt;\n    {% if is_granted(&#039;ROLE_ADMIN&#039;) %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot; style=&quot;color:var(--gold) !important;&quot;&gt;&lt;i class=&quot;fas fa-plus&quot;&gt;&lt;/i&gt; {{ &#039;nav.add&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% else %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% endif %}\n    &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;{{ &#039;nav.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    &lt;li&gt;\n      &lt;a href=&quot;#&quot; class=&quot;nav-cta&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n        &lt;i class=&quot;fas fa-paper-plane&quot;&gt;&lt;/i&gt; {{ &#039;nav.plan&#039;|trans }}\n      &lt;/a&gt;\n    &lt;/li&gt;\n\n    {# ── LANGUAGE SWITCHER ── #}\n    &lt;li&gt;\n      &lt;div class=&quot;lang-switcher&quot;&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;fr&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;fr&#039; %}active{% endif %}&quot;&gt;\n          🇫🇷 FR\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;en&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;en&#039; %}active{% endif %}&quot;&gt;\n          🇬🇧 EN\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;ar&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;ar&#039; %}active{% endif %}&quot;&gt;\n          🇹🇳 AR\n        &lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/li&gt;\n\n    {# ── LOGIN / USER ── #}\n    &lt;li&gt;\n      {% if app.user %}\n        &lt;div style=&quot;display:flex;align-items:center;gap:.6rem;&quot;&gt;\n          &lt;span class=&quot;nav-user&quot;&gt;\n            &lt;i class=&quot;fas fa-user-circle&quot;&gt;&lt;/i&gt;\n            {{ app.user.email }}\n          &lt;/span&gt;\n          &lt;a href=&quot;{{ path(&#039;app_logout&#039;) }}&quot; class=&quot;btn-login-nav&quot; title=&quot;{{ &#039;nav.logout&#039;|trans }}&quot;&gt;\n            &lt;i class=&quot;fas fa-sign-out-alt&quot;&gt;&lt;/i&gt; {{ &#039;nav.logout&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/div&gt;\n      {% else %}\n        &lt;button class=&quot;btn-login-nav&quot; onclick=&quot;openModal()&quot; type=&quot;button&quot;&gt;\n          &lt;i class=&quot;fas fa-user&quot;&gt;&lt;/i&gt; {{ &#039;nav.login&#039;|trans }}\n        &lt;/button&gt;\n      {% endif %}\n    &lt;/li&gt;\n  &lt;/ul&gt;\n&lt;/nav&gt;\n\n{# ── FLASH MESSAGES ── #}\n{% for msg in app.flashes(&#039;success&#039;) %}\n  &lt;div class=&quot;flash flash-success&quot;&gt;✅ {{ msg }}&lt;/div&gt;\n{% endfor %}\n{% for msg in app.flashes(&#039;error&#039;) %}\n  &lt;div class=&quot;flash flash-error&quot;&gt;❌ {{ msg }}&lt;/div&gt;\n{% endfor %}\n\n{% block body %}{% endblock %}\n\n{# ══ FOOTER ══════════════════════════════════════════════════════ #}\n&lt;footer&gt;\n  &lt;div class=&quot;footer-grid&quot;&gt;\n    &lt;div class=&quot;footer-brand&quot;&gt;\n      &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot; style=&quot;font-size:1.3rem&quot;&gt;Smart&lt;span style=&quot;color:#fff&quot;&gt;Trip&lt;/span&gt;&lt;/a&gt;\n      &lt;p&gt;{{ &#039;footer.desc&#039;|trans }}&lt;/p&gt;\n      &lt;div class=&quot;social-links&quot;&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-facebook-f&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-instagram&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-twitter&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-youtube&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.destinations&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.add_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.voyages&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.create_voyage&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.info&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#contact&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.contact&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;\n          &lt;a href=&quot;#&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n            &lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.sarah&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;footer-bottom&quot;&gt;\n    &lt;p&gt;© 2025 &lt;span&gt;SmartTrip&lt;/span&gt;. {{ &#039;footer.rights&#039;|trans }}&lt;/p&gt;\n    &lt;p&gt;{{ &#039;footer.made_with&#039;|trans }} &lt;span&gt;♥&lt;/span&gt; {{ &#039;footer.for&#039;|trans }}&lt;/p&gt;\n  &lt;/div&gt;\n&lt;/footer&gt;\n\n{# ══ CHAT SARAH ══════════════════════════════════════════════════ #}\n{% include &#039;chat/_popup.html.twig&#039; %}\n\n{# ══ JAVASCRIPT ══════════════════════════════════════════════════ #}\n{% block javascripts %}\n&lt;script&gt;\n  window.addEventListener(&#039;scroll&#039;, () =&gt; {\n    const nav = document.getElementById(&#039;navbar&#039;);\n    if (!nav) return;\n    nav.style.background = window.scrollY &gt; 50 ? &#039;rgba(13,27,42,0.99)&#039; : &#039;rgba(13,27,42,0.96)&#039;;\n  });\n\n  document.querySelectorAll(&#039;a[href^=&quot;#&quot;]&#039;).forEach(a =&gt; {\n    a.addEventListener(&#039;click&#039;, e =&gt; {\n      const href = a.getAttribute(&#039;href&#039;);\n      if (href === &#039;#&#039;) return;\n      const t = document.querySelector(href);\n      if (t) { e.preventDefault(); t.scrollIntoView({behavior:&#039;smooth&#039;}); }\n    });\n  });\n\n  function openModal() {\n    document.getElementById(&#039;loginModal&#039;).classList.add(&#039;open&#039;);\n    document.body.style.overflow = &#039;hidden&#039;;\n    setTimeout(() =&gt; document.getElementById(&#039;modal_email&#039;)?.focus(), 100);\n  }\n\n  function closeModal() {\n    document.getElementById(&#039;loginModal&#039;)?.classList.remove(&#039;open&#039;);\n    document.body.style.overflow = &#039;&#039;;\n    const video = document.getElementById(&#039;webcam&#039;);\n    if (video &amp;&amp; video.srcObject) {\n      video.srcObject.getTracks().forEach(t =&gt; t.stop());\n      video.srcObject = null;\n      cameraStarted = false;\n    }\n  }\n\n  document.getElementById(&#039;loginModal&#039;)?.addEventListener(&#039;click&#039;, function(e) {\n    if (e.target === this) closeModal();\n  });\n\n  document.addEventListener(&#039;keydown&#039;, e =&gt; { if (e.key === &#039;Escape&#039;) closeModal(); });\n\n  {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n    document.addEventListener(&#039;DOMContentLoaded&#039;, () =&gt; openModal());\n  {% endif %}\n\n  function switchTab(tab) {\n    const isPassword = tab === &#039;password&#039;;\n    document.getElementById(&#039;panel-password&#039;).style.display = isPassword ? &#039;block&#039; : &#039;none&#039;;\n    document.getElementById(&#039;panel-faceid&#039;).style.display   = isPassword ? &#039;none&#039;  : &#039;block&#039;;\n    const tabPwd  = document.getElementById(&#039;tab-password&#039;);\n    const tabFace = document.getElementById(&#039;tab-faceid&#039;);\n    if (isPassword) {\n      tabPwd.style.cssText  += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabFace.style.cssText += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n    } else {\n      tabFace.style.cssText += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabPwd.style.cssText  += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n      startCamera();\n    }\n  }\n\n  let cameraStarted = false;\n  function startCamera() {\n    if (cameraStarted) return;\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const result = document.getElementById(&#039;faceResult&#039;);\n    if (!video) return;\n    navigator.mediaDevices.getUserMedia({ video: true })\n      .then(stream =&gt; { video.srcObject = stream; cameraStarted = true; })\n      .catch(() =&gt; {\n        if (result) { result.textContent = &#039;❌ Caméra non accessible&#039;; result.style.color = &#039;#f87171&#039;; }\n      });\n  }\n\n  document.getElementById(&#039;faceLoginBtn&#039;)?.addEventListener(&#039;click&#039;, async () =&gt; {\n    const result = document.getElementById(&#039;faceResult&#039;);\n    const btn    = document.getElementById(&#039;faceLoginBtn&#039;);\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const canvas = document.getElementById(&#039;canvas&#039;);\n    const ctx    = canvas.getContext(&#039;2d&#039;);\n    ctx.drawImage(video, 0, 0, 320, 240);\n    result.textContent = &#039;⏳ Identification en cours...&#039;;\n    result.style.color = &#039;rgba(255,255,255,0.6)&#039;;\n    btn.disabled = true;\n    const formData = new FormData();\n    formData.append(&#039;face_image&#039;, canvas.toDataURL(&#039;image/jpeg&#039;));\n    try {\n      const res  = await fetch(&#039;/face-login&#039;, { method: &#039;POST&#039;, body: formData });\n      const data = await res.json();\n      if (data.success) {\n        result.textContent = `✅ Bienvenue ! (${data.confidence}%)`;\n        result.style.color = &#039;#4ade80&#039;;\n        setTimeout(() =&gt; window.location.href = data.redirect, 1200);\n      } else {\n        result.textContent = `❌ ${data.error ?? &#039;Visage non reconnu&#039;} (${data.confidence ?? 0}%)`;\n        result.style.color = &#039;#f87171&#039;;\n        btn.disabled = false;\n        btn.innerHTML = &#039;&lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; Réessayer&#039;;\n      }\n    } catch (e) {\n      result.textContent = &#039;❌ Erreur réseau&#039;;\n      result.style.color = &#039;#f87171&#039;;\n      btn.disabled = false;\n    }\n  });\n&lt;/script&gt;\n{% endblock %}\n\n&lt;/body&gt;\n&lt;/html&gt;\n&lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;{{ app.request.locale }}&quot; {% if app.request.locale == &#039;ar&#039; %}dir=&quot;rtl&quot;{% endif %}&gt;\n&lt;head&gt;\n  &lt;meta charset=&quot;UTF-8&quot;&gt;\n  &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;\n  &lt;title&gt;{% block title %}SmartTrip{% endblock %}&lt;/title&gt;\n  &lt;link href=&quot;https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&amp;family=Plus+Jakarta+Sans:wght@300;400;500;600;700&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;\n  &lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css&quot;&gt;\n  &lt;style&gt;\n    :root {\n      --navy:   #0d1b2a;\n      --navy-2: #112236;\n      --gold:   #c9a84c;\n      --gold-l: #e8c97a;\n      --cream:  #f5f0e8;\n      --white:  #ffffff;\n      --muted:  #7a8a99;\n      --shadow: 0 8px 32px rgba(13,27,42,0.18);\n    }\n    * { margin:0; padding:0; box-sizing:border-box; }\n    html { scroll-behavior:smooth; }\n    body { font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; background:var(--cream); color:var(--navy); overflow-x:hidden; }\n\n    {% if app.request.locale == &#039;ar&#039; %}\n    body { font-family: &#039;Segoe UI&#039;, &#039;Arial&#039;, sans-serif; direction: rtl; }\n    {% endif %}\n\n    /* ── NAV ── */\n    nav {\n      position:fixed; top:0; width:100%; z-index:1000;\n      display:flex; align-items:center; justify-content:space-between;\n      padding:1.1rem 5%;\n      background:rgba(13,27,42,0.96);\n      backdrop-filter:blur(20px);\n      border-bottom:1px solid rgba(201,168,76,0.2);\n      transition:all .3s;\n    }\n    .nav-logo { font-family:&#039;Playfair Display&#039;,serif; font-size:1.5rem; font-weight:700; color:var(--gold); text-decoration:none; letter-spacing:1px; }\n    .nav-logo span { color:var(--white); }\n    .nav-links { display:flex; gap:2rem; list-style:none; align-items:center; }\n    .nav-links a { color:rgba(255,255,255,0.7); text-decoration:none; font-size:.875rem; font-weight:500; transition:color .3s; position:relative; }\n    .nav-links a::after { content:&#039;&#039;; position:absolute; bottom:-4px; left:0; width:0; height:1px; background:var(--gold); transition:width .3s; }\n    .nav-links a:hover { color:var(--gold); }\n    .nav-links a:hover::after { width:100%; }\n    .nav-cta { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy) !important; padding:.55rem 1.4rem; border-radius:50px; font-weight:700 !important; }\n    .nav-cta::after { display:none !important; }\n\n    /* ── LANGUAGE SWITCHER ── */\n    .lang-switcher {\n      display:flex; align-items:center; gap:.3rem;\n      background:rgba(255,255,255,0.05);\n      border:1px solid rgba(201,168,76,0.2);\n      border-radius:50px;\n      padding:.3rem .5rem;\n    }\n    .lang-btn {\n      background:none; border:none; cursor:pointer;\n      color:rgba(255,255,255,0.45);\n      font-size:.72rem; font-weight:700;\n      padding:.25rem .5rem;\n      border-radius:50px;\n      transition:all .2s;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      letter-spacing:.5px;\n      text-decoration:none;\n      display:inline-flex; align-items:center; gap:.25rem;\n    }\n    .lang-btn:hover { color:var(--gold); background:rgba(201,168,76,0.1); }\n    .lang-btn.active { background:var(--gold); color:var(--navy); }\n    .lang-divider { color:rgba(255,255,255,0.15); font-size:.7rem; }\n\n    /* ── BOUTON LOGIN NAVBAR ── */\n    .btn-login-nav {\n      display:inline-flex; align-items:center; gap:.4rem;\n      padding:.5rem 1.1rem;\n      border:1px solid rgba(201,168,76,0.4);\n      border-radius:50px;\n      color:rgba(255,255,255,0.75) !important;\n      font-size:.8rem; font-weight:600;\n      cursor:pointer; transition:all .25s;\n      background:transparent;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      text-decoration:none;\n    }\n    .btn-login-nav::after { display:none !important; }\n    .btn-login-nav:hover { border-color:var(--gold); color:var(--gold) !important; background:rgba(201,168,76,0.08); }\n    .btn-login-nav i { font-size:.75rem; color:var(--gold); }\n\n    /* Badge user connecté */\n    .nav-user {\n      display:inline-flex; align-items:center; gap:.5rem;\n      padding:.45rem 1rem;\n      background:rgba(201,168,76,0.12);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:50px;\n      font-size:.78rem; color:var(--gold); font-weight:600;\n    }\n    .nav-user i { font-size:.75rem; }\n\n    /* ── MODAL LOGIN ── */\n    .modal-overlay {\n      display:none;\n      position:fixed; inset:0; z-index:9999;\n      background:rgba(7,16,26,0.85);\n      backdrop-filter:blur(8px);\n      align-items:center; justify-content:center;\n    }\n    .modal-overlay.open { display:flex; }\n    .modal-card {\n      background:rgba(17,34,54,0.98);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:20px;\n      padding:2.5rem 2.2rem;\n      width:100%; max-width:400px;\n      position:relative;\n      animation:modalIn .25s ease;\n    }\n    @keyframes modalIn {\n      from { opacity:0; transform:translateY(-20px) scale(0.97); }\n      to   { opacity:1; transform:translateY(0)     scale(1);    }\n    }\n    .modal-close {\n      position:absolute; top:1rem; right:1.1rem;\n      background:none; border:none; color:rgba(255,255,255,0.35);\n      font-size:1.2rem; cursor:pointer; transition:color .2s; line-height:1;\n    }\n    .modal-close:hover { color:var(--gold); }\n    .modal-logo { text-align:center; margin-bottom:1.6rem; }\n    .modal-logo h2 { font-family:&#039;Playfair Display&#039;,serif; font-size:1.6rem; font-weight:700; color:var(--gold); }\n    .modal-logo h2 span { color:var(--white); }\n    .modal-logo p { font-size:.75rem; color:rgba(255,255,255,0.35); margin-top:.3rem; }\n    .modal-field { margin-bottom:1.1rem; }\n    .modal-field label { display:block; font-size:.68rem; font-weight:700; letter-spacing:.12em; text-transform:uppercase; color:rgba(255,255,255,0.45); margin-bottom:.45rem; }\n    .modal-field input { width:100%; padding:.8rem 1rem; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.2); border-radius:10px; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .modal-field input:focus { border-color:var(--gold); }\n    .modal-field input::placeholder { color:rgba(255,255,255,0.2); }\n    .modal-remember { display:flex; align-items:center; gap:.5rem; margin-bottom:1.4rem; }\n    .modal-remember input[type=&quot;checkbox&quot;] { accent-color:var(--gold); }\n    .modal-remember label { font-size:.75rem; color:rgba(255,255,255,0.4); }\n    .btn-modal-submit { width:100%; padding:.9rem; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; border-radius:10px; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.9rem; font-weight:700; cursor:pointer; transition:transform .3s,box-shadow .3s; letter-spacing:.03em; }\n    .btn-modal-submit:hover { transform:translateY(-2px); box-shadow:0 10px 28px rgba(201,168,76,0.4); }\n    .modal-error { background:rgba(248,113,113,.1); border:1px solid rgba(248,113,113,.3); border-radius:8px; padding:.75rem 1rem; color:#fca5a5; font-size:.8rem; margin-bottom:1.1rem; text-align:center; }\n\n    /* ── FLASH ── */\n    .flash { padding:1rem 5%; margin-top:72px; font-size:.875rem; }\n    .flash-success { background:rgba(74,222,128,.1); border-left:3px solid #4ade80; color:#166534; }\n    .flash-error   { background:rgba(248,113,113,.1); border-left:3px solid #f87171; color:#991b1b; }\n\n    /* ── HERO ── */\n    .hero { min-height:100vh; position:relative; display:flex; align-items:center; overflow:hidden; }\n    .hero-bg { position:absolute; inset:0; background:url(&#039;https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1920&amp;q=80&#039;) center/cover no-repeat; }\n    .hero-overlay { position:absolute; inset:0; background:linear-gradient(135deg,rgba(13,27,42,0.95) 0%,rgba(13,27,42,0.65) 50%,rgba(13,27,42,0.4) 100%); }\n    .hero-content { position:relative; z-index:2; padding:0 5%; max-width:720px; }\n    .hero-badge { display:inline-flex; align-items:center; gap:.5rem; background:rgba(201,168,76,0.15); border:1px solid rgba(201,168,76,0.35); color:var(--gold); padding:.4rem 1rem; border-radius:50px; font-size:.75rem; font-weight:600; letter-spacing:1.5px; text-transform:uppercase; margin-bottom:1.5rem; }\n    .hero h1 { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(2.5rem,6vw,5rem); line-height:1.1; margin-bottom:1.5rem; color:var(--white); }\n    .hero h1 em { font-style:italic; color:var(--gold); }\n    .hero p { font-size:1.05rem; color:rgba(255,255,255,0.7); line-height:1.75; margin-bottom:2.5rem; max-width:500px; }\n    .hero-btns { display:flex; gap:1rem; flex-wrap:wrap; }\n    .hero-search { position:absolute; bottom:2.5rem; left:5%; right:5%; z-index:2; }\n    .search-box { background:rgba(13,27,42,0.92); border:1px solid rgba(201,168,76,0.25); border-radius:16px; padding:1.4rem 2rem; display:flex; gap:1rem; align-items:center; flex-wrap:wrap; backdrop-filter:blur(20px); }\n    .search-field { flex:1; min-width:140px; display:flex; flex-direction:column; gap:.25rem; }\n    .search-field label { font-size:.65rem; text-transform:uppercase; letter-spacing:1.2px; color:var(--gold); font-weight:700; }\n    .search-field input, .search-field select { background:transparent; border:none; outline:none; color:var(--white); font-size:.9rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; cursor:pointer; }\n    .search-field select option { background:var(--navy); }\n    .search-divider { width:1px; height:36px; background:rgba(201,168,76,0.2); }\n    .search-btn { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.85rem 1.6rem; border-radius:10px; font-weight:700; font-size:.875rem; display:flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; white-space:nowrap; }\n    .search-btn:hover { transform:translateY(-2px); box-shadow:0 8px 25px rgba(201,168,76,0.4); }\n\n    /* ── BUTTONS ── */\n    .btn-primary { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); padding:.85rem 2rem; border-radius:50px; font-weight:700; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-primary:hover { transform:translateY(-3px); box-shadow:0 12px 35px rgba(201,168,76,0.4); }\n    .btn-outline-light { border:1px solid rgba(255,255,255,0.35); color:var(--white); padding:.85rem 2rem; border-radius:50px; font-weight:500; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; backdrop-filter:blur(10px); transition:border-color .3s,background .3s; cursor:pointer; }\n    .btn-outline-light:hover { border-color:var(--gold); background:rgba(201,168,76,0.1); color:var(--gold); }\n    .btn-gold { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.6rem 1.4rem; border-radius:50px; font-weight:700; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:transform .3s,box-shadow .3s; }\n    .btn-gold:hover { transform:translateY(-2px); box-shadow:0 8px 20px rgba(201,168,76,0.4); }\n    .btn-navy { background:var(--navy); color:var(--gold); border:1px solid rgba(201,168,76,0.3); padding:.6rem 1.4rem; border-radius:50px; font-weight:600; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:all .3s; }\n    .btn-navy:hover { background:var(--gold); color:var(--navy); }\n    .btn-danger-sm { background:rgba(220,38,38,0.1); color:#dc2626; border:1px solid rgba(220,38,38,0.2); padding:.4rem .9rem; border-radius:8px; cursor:pointer; font-size:.78rem; font-weight:600; text-decoration:none; display:inline-flex; align-items:center; gap:.3rem; transition:all .3s; }\n    .btn-danger-sm:hover { background:rgba(220,38,38,0.2); }\n\n    /* ── SECTIONS ── */\n    section { padding:5rem 5%; }\n    .section-label { display:inline-block; color:var(--gold); font-size:.72rem; font-weight:700; letter-spacing:2.5px; text-transform:uppercase; margin-bottom:.75rem; }\n    .section-title { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(1.8rem,3.5vw,2.8rem); color:var(--navy); line-height:1.2; margin-bottom:.75rem; }\n    .section-title.light { color:var(--white); }\n    .section-sub { color:var(--muted); font-size:.95rem; line-height:1.75; max-width:480px; }\n    .section-header { display:flex; justify-content:space-between; align-items:flex-end; margin-bottom:2.5rem; flex-wrap:wrap; gap:1rem; }\n\n    /* ── DESTINATIONS GRID ── */\n    #destinations { background:var(--cream); }\n    .dest-grid { display:grid; grid-template-columns:repeat(3,1fr); grid-template-rows:auto auto; gap:1.2rem; }\n    .dest-card { position:relative; border-radius:14px; overflow:hidden; cursor:pointer; }\n    .dest-card-featured { grid-row:1/3; }\n    .dest-card img { width:100%; height:100%; min-height:220px; object-fit:cover; transition:transform .6s; }\n    .dest-card-featured img { min-height:480px; }\n    .dest-card:hover img { transform:scale(1.07); }\n    .dest-overlay { position:absolute; inset:0; background:linear-gradient(to top,rgba(13,27,42,0.92) 0%,transparent 55%); display:flex; flex-direction:column; justify-content:flex-end; padding:1.6rem; }\n    .dest-badge { background:rgba(201,168,76,0.92); color:var(--navy); font-size:.65rem; font-weight:700; padding:.2rem .6rem; border-radius:50px; display:inline-block; margin-bottom:.6rem; width:fit-content; letter-spacing:.5px; text-transform:uppercase; }\n    .dest-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.3rem; color:var(--white); margin-bottom:.25rem; }\n    .dest-card-featured .dest-name { font-size:1.7rem; }\n    .dest-info { display:flex; justify-content:space-between; align-items:center; }\n    .dest-price { color:var(--gold); font-weight:700; font-size:.95rem; }\n    .dest-action { width:34px; height:34px; background:var(--gold); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--navy); font-size:.75rem; opacity:0; transform:translateY(8px); transition:opacity .3s,transform .3s; text-decoration:none; }\n    .dest-card:hover .dest-action { opacity:1; transform:translateY(0); }\n\n    /* ── PACKAGES ── */\n    #packages { background:var(--navy); }\n    .packages-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:1.4rem; margin-top:2.5rem; }\n    .pkg-card { background:var(--navy-2); border:1px solid rgba(201,168,76,0.12); border-radius:14px; overflow:hidden; transition:transform .3s,box-shadow .3s,border-color .3s; position:relative; }\n    .pkg-card:hover { transform:translateY(-8px); box-shadow:0 25px 60px rgba(0,0,0,0.4); border-color:rgba(201,168,76,0.35); }\n    .pkg-card.featured { border-color:var(--gold); }\n    .pkg-ribbon { position:absolute; top:1rem; right:1rem; background:var(--gold); color:var(--navy); font-size:.65rem; font-weight:700; padding:.25rem .75rem; border-radius:50px; z-index:1; letter-spacing:.5px; }\n    .pkg-img { height:190px; overflow:hidden; }\n    .pkg-img img { width:100%; height:100%; object-fit:cover; transition:transform .5s; }\n    .pkg-card:hover .pkg-img img { transform:scale(1.08); }\n    .pkg-body { padding:1.4rem; }\n    .pkg-meta { display:flex; gap:.8rem; font-size:.75rem; color:rgba(255,255,255,0.5); margin-bottom:.9rem; flex-wrap:wrap; }\n    .pkg-meta span { display:flex; align-items:center; gap:.3rem; }\n    .pkg-meta i { color:var(--gold); }\n    .pkg-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.15rem; color:var(--white); margin-bottom:.4rem; }\n    .pkg-desc { color:rgba(255,255,255,0.55); font-size:.82rem; line-height:1.65; margin-bottom:1.1rem; }\n    .pkg-features { list-style:none; margin-bottom:1.3rem; }\n    .pkg-features li { font-size:.8rem; color:rgba(255,255,255,0.6); display:flex; align-items:center; gap:.45rem; padding:.25rem 0; }\n    .pkg-features i { color:var(--gold); font-size:.65rem; }\n    .pkg-footer { display:flex; justify-content:space-between; align-items:center; border-top:1px solid rgba(201,168,76,0.12); padding-top:1.1rem; }\n    .pkg-price-label { font-size:.7rem; color:rgba(255,255,255,0.45); }\n    .pkg-price { font-size:1.4rem; font-weight:700; color:var(--gold); }\n    .pkg-price small { font-size:.7rem; color:rgba(255,255,255,0.45); }\n\n    /* ── ABOUT ── */\n    #about { background:var(--cream); display:grid; grid-template-columns:1fr 1fr; gap:5rem; align-items:center; }\n    .about-img-wrap { position:relative; }\n    .about-img-main { width:100%; height:480px; object-fit:cover; border-radius:16px; }\n    .about-img-badge { position:absolute; bottom:-1.5rem; right:-1.5rem; background:var(--gold); color:var(--navy); border-radius:14px; padding:1.4rem; text-align:center; box-shadow:0 20px 50px rgba(201,168,76,0.3); }\n    .about-img-badge strong { font-size:2.2rem; display:block; line-height:1; font-family:&#039;Playfair Display&#039;,serif; }\n    .about-img-badge span { font-size:.75rem; font-weight:600; letter-spacing:.5px; }\n    .about-features { display:grid; grid-template-columns:1fr 1fr; gap:1rem; margin:1.8rem 0; }\n    .about-feat { display:flex; gap:.9rem; align-items:flex-start; background:var(--white); border:1px solid rgba(201,168,76,0.12); padding:1.1rem; border-radius:12px; transition:border-color .3s,box-shadow .3s; }\n    .about-feat:hover { border-color:var(--gold); box-shadow:var(--shadow); }\n    .about-feat-icon { width:40px; height:40px; background:rgba(201,168,76,0.1); border-radius:10px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .about-feat h4 { font-size:.875rem; color:var(--navy); margin-bottom:.25rem; font-weight:600; }\n    .about-feat p { font-size:.78rem; color:var(--muted); line-height:1.5; }\n\n    /* ── CONTACT ── */\n    #contact { background:var(--navy); display:grid; grid-template-columns:1fr 1.5fr; gap:5rem; align-items:start; }\n    .contact-items { display:flex; flex-direction:column; gap:1.4rem; margin-top:2rem; }\n    .contact-item { display:flex; gap:1rem; align-items:flex-start; }\n    .contact-icon { width:46px; height:46px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:12px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .contact-item h4 { font-size:.78rem; color:rgba(255,255,255,0.5); margin-bottom:.2rem; text-transform:uppercase; letter-spacing:.5px; }\n    .contact-item p { color:var(--white); font-size:.9rem; }\n    .contact-form { background:rgba(255,255,255,0.04); border:1px solid rgba(201,168,76,0.15); border-radius:18px; padding:2.2rem; }\n    .contact-form h3 { font-family:&#039;Playfair Display&#039;,serif; margin-bottom:1.4rem; color:var(--white); font-size:1.3rem; }\n    .form-row { display:grid; grid-template-columns:1fr 1fr; gap:1rem; }\n    .form-group { margin-bottom:1.1rem; }\n    .form-group label { display:block; font-size:.72rem; color:rgba(255,255,255,0.55); font-weight:600; letter-spacing:.5px; text-transform:uppercase; margin-bottom:.45rem; }\n    .form-group input, .form-group select, .form-group textarea { width:100%; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.15); border-radius:10px; padding:.75rem 1rem; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color:var(--gold); }\n    .form-group textarea { resize:vertical; min-height:100px; }\n    .form-group select option { background:var(--navy); }\n    .btn-submit { width:100%; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.95rem; border-radius:10px; font-weight:700; font-size:.95rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; display:flex; align-items:center; justify-content:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-submit:hover { transform:translateY(-2px); box-shadow:0 12px 30px rgba(201,168,76,0.4); }\n\n    /* ── FOOTER ── */\n    footer { background:#07101a; border-top:1px solid rgba(201,168,76,0.1); padding:3.5rem 5% 2rem; }\n    .footer-grid { display:grid; grid-template-columns:1.5fr 1fr 1fr 1fr; gap:3rem; margin-bottom:2.5rem; }\n    .footer-brand p { color:rgba(255,255,255,0.45); font-size:.82rem; line-height:1.7; margin:1rem 0 1.3rem; }\n    .social-links { display:flex; gap:.7rem; }\n    .social-link { width:36px; height:36px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--gold); font-size:.8rem; text-decoration:none; transition:background .3s,transform .3s; }\n    .social-link:hover { background:var(--gold); color:var(--navy); transform:translateY(-3px); }\n    .footer-col h4 { font-size:.82rem; font-weight:700; color:var(--white); margin-bottom:1rem; letter-spacing:.5px; text-transform:uppercase; }\n    .footer-col ul { list-style:none; }\n    .footer-col ul li { margin-bottom:.55rem; }\n    .footer-col ul a { color:rgba(255,255,255,0.45); text-decoration:none; font-size:.82rem; transition:color .3s; display:flex; align-items:center; gap:.35rem; }\n    .footer-col ul a:hover { color:var(--gold); }\n    .footer-bottom { border-top:1px solid rgba(201,168,76,0.1); padding-top:1.4rem; display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:1rem; }\n    .footer-bottom p { color:rgba(255,255,255,0.35); font-size:.78rem; }\n    .footer-bottom span { color:var(--gold); }\n\n    /* ── RESPONSIVE ── */\n    @media(max-width:1024px) {\n      .dest-grid { grid-template-columns:1fr 1fr; }\n      .dest-card-featured { grid-row:auto; }\n      .packages-grid { grid-template-columns:1fr 1fr; }\n      #about,#contact { grid-template-columns:1fr; gap:3rem; }\n      .footer-grid { grid-template-columns:1fr 1fr; }\n    }\n    @media(max-width:768px) {\n      .nav-links { display:none; }\n      .dest-grid,.packages-grid { grid-template-columns:1fr; }\n      .search-box { flex-direction:column; }\n      .search-divider { display:none; }\n      .about-features,.form-row { grid-template-columns:1fr; }\n      .footer-grid { grid-template-columns:1fr; gap:2rem; }\n      .about-img-badge { right:1rem; bottom:1rem; }\n      #chat-widget { bottom:16px !important; right:16px !important; }\n      #chat-popup  { width:calc(100vw - 32px) !important; }\n    }\n\n    @keyframes fadeInUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }\n    .fade-in  { animation:fadeInUp .8s ease forwards; }\n    .delay-1  { animation-delay:.2s; opacity:0; }\n    .delay-2  { animation-delay:.4s; opacity:0; }\n\n    {% block extra_css %}{% endblock %}\n  &lt;/style&gt;\n  {% block stylesheets %}{% endblock %}\n&lt;/head&gt;\n&lt;body&gt;\n\n{# ══ MODAL LOGIN ══════════════════════════════════════════════════ #}\n{% if not app.user %}\n&lt;div class=&quot;modal-overlay&quot; id=&quot;loginModal&quot;&gt;\n  &lt;div class=&quot;modal-card&quot;&gt;\n    &lt;button class=&quot;modal-close&quot; onclick=&quot;closeModal()&quot; title=&quot;Fermer&quot;&gt;✕&lt;/button&gt;\n    &lt;div class=&quot;modal-logo&quot;&gt;\n      &lt;h2&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/h2&gt;\n      &lt;p&gt;{{ &#039;login.title&#039;|trans }}&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;div style=&quot;display:flex; gap:.5rem; margin-bottom:1.5rem;&quot;&gt;\n      &lt;button onclick=&quot;switchTab(&#039;password&#039;)&quot; id=&quot;tab-password&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:700;\n               background:linear-gradient(135deg,var(--gold),var(--gold-l));\n               color:var(--navy); border:1px solid var(--gold); transition:all .3s;&quot;&gt;\n        🔑 {{ &#039;login.password_tab&#039;|trans }}\n      &lt;/button&gt;\n      &lt;button onclick=&quot;switchTab(&#039;faceid&#039;)&quot; id=&quot;tab-faceid&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:600;\n               background:transparent; color:rgba(255,255,255,0.6);\n               border:1px solid rgba(201,168,76,0.3); transition:all .3s;&quot;&gt;\n        📷 {{ &#039;login.faceid_tab&#039;|trans }}\n      &lt;/button&gt;\n    &lt;/div&gt;\n    {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n      &lt;div class=&quot;modal-error&quot;&gt;❌ {{ error.messageKey|trans(error.messageData, &#039;security&#039;) }}&lt;/div&gt;\n    {% endif %}\n    &lt;div id=&quot;panel-password&quot;&gt;\n      &lt;form method=&quot;POST&quot; action=&quot;{{ path(&#039;app_login&#039;) }}&quot;&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_email&quot;&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;email&quot; id=&quot;modal_email&quot; name=&quot;email&quot; value=&quot;{{ last_username ?? &#039;&#039; }}&quot; placeholder=&quot;votre@email.com&quot; autocomplete=&quot;email&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_password&quot;&gt;{{ &#039;login.password&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;password&quot; id=&quot;modal_password&quot; name=&quot;password&quot; placeholder=&quot;••••••••&quot; autocomplete=&quot;current-password&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-remember&quot;&gt;\n          &lt;input type=&quot;checkbox&quot; id=&quot;modal_remember&quot; name=&quot;_remember_me&quot;&gt;\n          &lt;label for=&quot;modal_remember&quot;&gt;{{ &#039;login.remember&#039;|trans }}&lt;/label&gt;\n        &lt;/div&gt;\n        &lt;input type=&quot;hidden&quot; name=&quot;_csrf_token&quot; value=&quot;{{ csrf_token(&#039;authenticate&#039;) }}&quot;&gt;\n        &lt;button type=&quot;submit&quot; class=&quot;btn-modal-submit&quot;&gt;\n          &lt;i class=&quot;fas fa-sign-in-alt&quot;&gt;&lt;/i&gt; {{ &#039;login.submit&#039;|trans }}\n        &lt;/button&gt;\n      &lt;/form&gt;\n    &lt;/div&gt;\n    &lt;div id=&quot;panel-faceid&quot; style=&quot;display:none;&quot;&gt;\n      &lt;div class=&quot;modal-field&quot;&gt;\n        &lt;label&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n        &lt;input type=&quot;email&quot; id=&quot;faceEmail&quot; placeholder=&quot;votre@email.com&quot; style=&quot;width:100%;padding:.8rem 1rem;background:rgba(255,255,255,0.06);border:1px solid rgba(201,168,76,0.2);border-radius:10px;color:var(--white);font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;font-size:.875rem;outline:none;&quot;&gt;\n      &lt;/div&gt;\n      &lt;div style=&quot;position:relative;border-radius:12px;overflow:hidden;border:1px solid rgba(201,168,76,0.3);margin-bottom:1rem;background:#000;&quot;&gt;\n        &lt;video id=&quot;webcam&quot; autoplay playsinline style=&quot;width:100%;height:200px;display:block;object-fit:cover;&quot;&gt;&lt;/video&gt;\n        &lt;canvas id=&quot;canvas&quot; width=&quot;320&quot; height=&quot;240&quot; style=&quot;display:none;&quot;&gt;&lt;/canvas&gt;\n        &lt;div style=&quot;position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none;&quot;&gt;\n          &lt;div style=&quot;width:110px;height:135px;border:2px solid var(--gold);border-radius:55px;opacity:.7;box-shadow:0 0 20px rgba(201,168,76,0.3);&quot;&gt;&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div style=&quot;position:absolute;bottom:.5rem;left:0;right:0;text-align:center;font-size:.7rem;color:rgba(255,255,255,0.5);&quot;&gt;\n          {{ &#039;login.face_center&#039;|trans }}\n        &lt;/div&gt;\n      &lt;/div&gt;\n      &lt;button id=&quot;faceLoginBtn&quot; class=&quot;btn-modal-submit&quot; type=&quot;button&quot;&gt;\n        &lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; {{ &#039;login.face_scan&#039;|trans }}\n      &lt;/button&gt;\n      &lt;p id=&quot;faceResult&quot; style=&quot;text-align:center;margin-top:.75rem;font-size:.82rem;min-height:1.2rem;color:rgba(255,255,255,0.6);&quot;&gt;&lt;/p&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/div&gt;\n{% endif %}\n\n{# ══ NAVBAR ══════════════════════════════════════════════════════ #}\n&lt;nav id=&quot;navbar&quot;&gt;\n  &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot;&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/a&gt;\n  &lt;ul class=&quot;nav-links&quot;&gt;\n    {% if is_granted(&#039;ROLE_ADMIN&#039;) %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot; style=&quot;color:var(--gold) !important;&quot;&gt;&lt;i class=&quot;fas fa-plus&quot;&gt;&lt;/i&gt; {{ &#039;nav.add&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% else %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% endif %}\n    &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;{{ &#039;nav.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    &lt;li&gt;\n      &lt;a href=&quot;#&quot; class=&quot;nav-cta&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n        &lt;i class=&quot;fas fa-paper-plane&quot;&gt;&lt;/i&gt; {{ &#039;nav.plan&#039;|trans }}\n      &lt;/a&gt;\n    &lt;/li&gt;\n\n    {# ── LANGUAGE SWITCHER ── #}\n    &lt;li&gt;\n      &lt;div class=&quot;lang-switcher&quot;&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;fr&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;fr&#039; %}active{% endif %}&quot;&gt;\n          🇫🇷 FR\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;en&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;en&#039; %}active{% endif %}&quot;&gt;\n          🇬🇧 EN\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;ar&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;ar&#039; %}active{% endif %}&quot;&gt;\n          🇹🇳 AR\n        &lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/li&gt;\n\n    {# ── LOGIN / USER ── #}\n    &lt;li&gt;\n      {% if app.user %}\n        &lt;div style=&quot;display:flex;align-items:center;gap:.6rem;&quot;&gt;\n          &lt;span class=&quot;nav-user&quot;&gt;\n            &lt;i class=&quot;fas fa-user-circle&quot;&gt;&lt;/i&gt;\n            {{ app.user.email }}\n          &lt;/span&gt;\n          &lt;a href=&quot;{{ path(&#039;app_logout&#039;) }}&quot; class=&quot;btn-login-nav&quot; title=&quot;{{ &#039;nav.logout&#039;|trans }}&quot;&gt;\n            &lt;i class=&quot;fas fa-sign-out-alt&quot;&gt;&lt;/i&gt; {{ &#039;nav.logout&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/div&gt;\n      {% else %}\n        &lt;button class=&quot;btn-login-nav&quot; onclick=&quot;openModal()&quot; type=&quot;button&quot;&gt;\n          &lt;i class=&quot;fas fa-user&quot;&gt;&lt;/i&gt; {{ &#039;nav.login&#039;|trans }}\n        &lt;/button&gt;\n      {% endif %}\n    &lt;/li&gt;\n  &lt;/ul&gt;\n&lt;/nav&gt;\n\n{# ── FLASH MESSAGES ── #}\n{% for msg in app.flashes(&#039;success&#039;) %}\n  &lt;div class=&quot;flash flash-success&quot;&gt;✅ {{ msg }}&lt;/div&gt;\n{% endfor %}\n{% for msg in app.flashes(&#039;error&#039;) %}\n  &lt;div class=&quot;flash flash-error&quot;&gt;❌ {{ msg }}&lt;/div&gt;\n{% endfor %}\n\n{% block body %}{% endblock %}\n\n{# ══ FOOTER ══════════════════════════════════════════════════════ #}\n&lt;footer&gt;\n  &lt;div class=&quot;footer-grid&quot;&gt;\n    &lt;div class=&quot;footer-brand&quot;&gt;\n      &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot; style=&quot;font-size:1.3rem&quot;&gt;Smart&lt;span style=&quot;color:#fff&quot;&gt;Trip&lt;/span&gt;&lt;/a&gt;\n      &lt;p&gt;{{ &#039;footer.desc&#039;|trans }}&lt;/p&gt;\n      &lt;div class=&quot;social-links&quot;&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-facebook-f&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-instagram&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-twitter&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-youtube&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.destinations&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.add_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.voyages&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.create_voyage&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.info&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#contact&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.contact&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;\n          &lt;a href=&quot;#&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n            &lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.sarah&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;footer-bottom&quot;&gt;\n    &lt;p&gt;© 2025 &lt;span&gt;SmartTrip&lt;/span&gt;. {{ &#039;footer.rights&#039;|trans }}&lt;/p&gt;\n    &lt;p&gt;{{ &#039;footer.made_with&#039;|trans }} &lt;span&gt;♥&lt;/span&gt; {{ &#039;footer.for&#039;|trans }}&lt;/p&gt;\n  &lt;/div&gt;\n&lt;/footer&gt;\n\n{# ══ CHAT SARAH ══════════════════════════════════════════════════ #}\n{% include &#039;chat/_popup.html.twig&#039; %}\n\n{# ══ JAVASCRIPT ══════════════════════════════════════════════════ #}\n{% block javascripts %}\n&lt;script&gt;\n  window.addEventListener(&#039;scroll&#039;, () =&gt; {\n    const nav = document.getElementById(&#039;navbar&#039;);\n    if (!nav) return;\n    nav.style.background = window.scrollY &gt; 50 ? &#039;rgba(13,27,42,0.99)&#039; : &#039;rgba(13,27,42,0.96)&#039;;\n  });\n\n  document.querySelectorAll(&#039;a[href^=&quot;#&quot;]&#039;).forEach(a =&gt; {\n    a.addEventListener(&#039;click&#039;, e =&gt; {\n      const href = a.getAttribute(&#039;href&#039;);\n      if (href === &#039;#&#039;) return;\n      const t = document.querySelector(href);\n      if (t) { e.preventDefault(); t.scrollIntoView({behavior:&#039;smooth&#039;}); }\n    });\n  });\n\n  function openModal() {\n    document.getElementById(&#039;loginModal&#039;).classList.add(&#039;open&#039;);\n    document.body.style.overflow = &#039;hidden&#039;;\n    setTimeout(() =&gt; document.getElementById(&#039;modal_email&#039;)?.focus(), 100);\n  }\n\n  function closeModal() {\n    document.getElementById(&#039;loginModal&#039;)?.classList.remove(&#039;open&#039;);\n    document.body.style.overflow = &#039;&#039;;\n    const video = document.getElementById(&#039;webcam&#039;);\n    if (video &amp;&amp; video.srcObject) {\n      video.srcObject.getTracks().forEach(t =&gt; t.stop());\n      video.srcObject = null;\n      cameraStarted = false;\n    }\n  }\n\n  document.getElementById(&#039;loginModal&#039;)?.addEventListener(&#039;click&#039;, function(e) {\n    if (e.target === this) closeModal();\n  });\n\n  document.addEventListener(&#039;keydown&#039;, e =&gt; { if (e.key === &#039;Escape&#039;) closeModal(); });\n\n  {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n    document.addEventListener(&#039;DOMContentLoaded&#039;, () =&gt; openModal());\n  {% endif %}\n\n  function switchTab(tab) {\n    const isPassword = tab === &#039;password&#039;;\n    document.getElementById(&#039;panel-password&#039;).style.display = isPassword ? &#039;block&#039; : &#039;none&#039;;\n    document.getElementById(&#039;panel-faceid&#039;).style.display   = isPassword ? &#039;none&#039;  : &#039;block&#039;;\n    const tabPwd  = document.getElementById(&#039;tab-password&#039;);\n    const tabFace = document.getElementById(&#039;tab-faceid&#039;);\n    if (isPassword) {\n      tabPwd.style.cssText  += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabFace.style.cssText += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n    } else {\n      tabFace.style.cssText += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabPwd.style.cssText  += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n      startCamera();\n    }\n  }\n\n  let cameraStarted = false;\n  function startCamera() {\n    if (cameraStarted) return;\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const result = document.getElementById(&#039;faceResult&#039;);\n    if (!video) return;\n    navigator.mediaDevices.getUserMedia({ video: true })\n      .then(stream =&gt; { video.srcObject = stream; cameraStarted = true; })\n      .catch(() =&gt; {\n        if (result) { result.textContent = &#039;❌ Caméra non accessible&#039;; result.style.color = &#039;#f87171&#039;; }\n      });\n  }\n\n  document.getElementById(&#039;faceLoginBtn&#039;)?.addEventListener(&#039;click&#039;, async () =&gt; {\n    const result = document.getElementById(&#039;faceResult&#039;);\n    const btn    = document.getElementById(&#039;faceLoginBtn&#039;);\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const canvas = document.getElementById(&#039;canvas&#039;);\n    const ctx    = canvas.getContext(&#039;2d&#039;);\n    ctx.drawImage(video, 0, 0, 320, 240);\n    result.textContent = &#039;⏳ Identification en cours...&#039;;\n    result.style.color = &#039;rgba(255,255,255,0.6)&#039;;\n    btn.disabled = true;\n    const formData = new FormData();\n    formData.append(&#039;face_image&#039;, canvas.toDataURL(&#039;image/jpeg&#039;));\n    try {\n      const res  = await fetch(&#039;/face-login&#039;, { method: &#039;POST&#039;, body: formData });\n      const data = await res.json();\n      if (data.success) {\n        result.textContent = `✅ Bienvenue ! (${data.confidence}%)`;\n        result.style.color = &#039;#4ade80&#039;;\n        setTimeout(() =&gt; window.location.href = data.redirect, 1200);\n      } else {\n        result.textContent = `❌ ${data.error ?? &#039;Visage non reconnu&#039;} (${data.confidence ?? 0}%)`;\n        result.style.color = &#039;#f87171&#039;;\n        btn.disabled = false;\n        btn.innerHTML = &#039;&lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; Réessayer&#039;;\n      }\n    } catch (e) {\n      result.textContent = &#039;❌ Erreur réseau&#039;;\n      result.style.color = &#039;#f87171&#039;;\n      btn.disabled = false;\n    }\n  });\n&lt;/script&gt;\n{% endblock %}\n\n&lt;/body&gt;\n&lt;/html&gt;\n&lt;!DOCTYPE html&gt;\n&lt;html lang=&quot;{{ app.request.locale }}&quot; {% if app.request.locale == &#039;ar&#039; %}dir=&quot;rtl&quot;{% endif %}&gt;\n&lt;head&gt;\n  &lt;meta charset=&quot;UTF-8&quot;&gt;\n  &lt;meta name=&quot;viewport&quot; content=&quot;width=device-width, initial-scale=1.0&quot;&gt;\n  &lt;title&gt;{% block title %}SmartTrip{% endblock %}&lt;/title&gt;\n  &lt;link href=&quot;https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,600;0,700;1,400&amp;family=Plus+Jakarta+Sans:wght@300;400;500;600;700&amp;display=swap&quot; rel=&quot;stylesheet&quot;&gt;\n  &lt;link rel=&quot;stylesheet&quot; href=&quot;https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css&quot;&gt;\n  &lt;style&gt;\n    :root {\n      --navy:   #0d1b2a;\n      --navy-2: #112236;\n      --gold:   #c9a84c;\n      --gold-l: #e8c97a;\n      --cream:  #f5f0e8;\n      --white:  #ffffff;\n      --muted:  #7a8a99;\n      --shadow: 0 8px 32px rgba(13,27,42,0.18);\n    }\n    * { margin:0; padding:0; box-sizing:border-box; }\n    html { scroll-behavior:smooth; }\n    body { font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; background:var(--cream); color:var(--navy); overflow-x:hidden; }\n\n    {% if app.request.locale == &#039;ar&#039; %}\n    body { font-family: &#039;Segoe UI&#039;, &#039;Arial&#039;, sans-serif; direction: rtl; }\n    {% endif %}\n\n    /* ── NAV ── */\n    nav {\n      position:fixed; top:0; width:100%; z-index:1000;\n      display:flex; align-items:center; justify-content:space-between;\n      padding:1.1rem 5%;\n      background:rgba(13,27,42,0.96);\n      backdrop-filter:blur(20px);\n      border-bottom:1px solid rgba(201,168,76,0.2);\n      transition:all .3s;\n    }\n    .nav-logo { font-family:&#039;Playfair Display&#039;,serif; font-size:1.5rem; font-weight:700; color:var(--gold); text-decoration:none; letter-spacing:1px; }\n    .nav-logo span { color:var(--white); }\n    .nav-links { display:flex; gap:2rem; list-style:none; align-items:center; }\n    .nav-links a { color:rgba(255,255,255,0.7); text-decoration:none; font-size:.875rem; font-weight:500; transition:color .3s; position:relative; }\n    .nav-links a::after { content:&#039;&#039;; position:absolute; bottom:-4px; left:0; width:0; height:1px; background:var(--gold); transition:width .3s; }\n    .nav-links a:hover { color:var(--gold); }\n    .nav-links a:hover::after { width:100%; }\n    .nav-cta { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy) !important; padding:.55rem 1.4rem; border-radius:50px; font-weight:700 !important; }\n    .nav-cta::after { display:none !important; }\n\n    /* ── LANGUAGE SWITCHER ── */\n    .lang-switcher {\n      display:flex; align-items:center; gap:.3rem;\n      background:rgba(255,255,255,0.05);\n      border:1px solid rgba(201,168,76,0.2);\n      border-radius:50px;\n      padding:.3rem .5rem;\n    }\n    .lang-btn {\n      background:none; border:none; cursor:pointer;\n      color:rgba(255,255,255,0.45);\n      font-size:.72rem; font-weight:700;\n      padding:.25rem .5rem;\n      border-radius:50px;\n      transition:all .2s;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      letter-spacing:.5px;\n      text-decoration:none;\n      display:inline-flex; align-items:center; gap:.25rem;\n    }\n    .lang-btn:hover { color:var(--gold); background:rgba(201,168,76,0.1); }\n    .lang-btn.active { background:var(--gold); color:var(--navy); }\n    .lang-divider { color:rgba(255,255,255,0.15); font-size:.7rem; }\n\n    /* ── BOUTON LOGIN NAVBAR ── */\n    .btn-login-nav {\n      display:inline-flex; align-items:center; gap:.4rem;\n      padding:.5rem 1.1rem;\n      border:1px solid rgba(201,168,76,0.4);\n      border-radius:50px;\n      color:rgba(255,255,255,0.75) !important;\n      font-size:.8rem; font-weight:600;\n      cursor:pointer; transition:all .25s;\n      background:transparent;\n      font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;\n      text-decoration:none;\n    }\n    .btn-login-nav::after { display:none !important; }\n    .btn-login-nav:hover { border-color:var(--gold); color:var(--gold) !important; background:rgba(201,168,76,0.08); }\n    .btn-login-nav i { font-size:.75rem; color:var(--gold); }\n\n    /* Badge user connecté */\n    .nav-user {\n      display:inline-flex; align-items:center; gap:.5rem;\n      padding:.45rem 1rem;\n      background:rgba(201,168,76,0.12);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:50px;\n      font-size:.78rem; color:var(--gold); font-weight:600;\n    }\n    .nav-user i { font-size:.75rem; }\n\n    /* ── MODAL LOGIN ── */\n    .modal-overlay {\n      display:none;\n      position:fixed; inset:0; z-index:9999;\n      background:rgba(7,16,26,0.85);\n      backdrop-filter:blur(8px);\n      align-items:center; justify-content:center;\n    }\n    .modal-overlay.open { display:flex; }\n    .modal-card {\n      background:rgba(17,34,54,0.98);\n      border:1px solid rgba(201,168,76,0.25);\n      border-radius:20px;\n      padding:2.5rem 2.2rem;\n      width:100%; max-width:400px;\n      position:relative;\n      animation:modalIn .25s ease;\n    }\n    @keyframes modalIn {\n      from { opacity:0; transform:translateY(-20px) scale(0.97); }\n      to   { opacity:1; transform:translateY(0)     scale(1);    }\n    }\n    .modal-close {\n      position:absolute; top:1rem; right:1.1rem;\n      background:none; border:none; color:rgba(255,255,255,0.35);\n      font-size:1.2rem; cursor:pointer; transition:color .2s; line-height:1;\n    }\n    .modal-close:hover { color:var(--gold); }\n    .modal-logo { text-align:center; margin-bottom:1.6rem; }\n    .modal-logo h2 { font-family:&#039;Playfair Display&#039;,serif; font-size:1.6rem; font-weight:700; color:var(--gold); }\n    .modal-logo h2 span { color:var(--white); }\n    .modal-logo p { font-size:.75rem; color:rgba(255,255,255,0.35); margin-top:.3rem; }\n    .modal-field { margin-bottom:1.1rem; }\n    .modal-field label { display:block; font-size:.68rem; font-weight:700; letter-spacing:.12em; text-transform:uppercase; color:rgba(255,255,255,0.45); margin-bottom:.45rem; }\n    .modal-field input { width:100%; padding:.8rem 1rem; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.2); border-radius:10px; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .modal-field input:focus { border-color:var(--gold); }\n    .modal-field input::placeholder { color:rgba(255,255,255,0.2); }\n    .modal-remember { display:flex; align-items:center; gap:.5rem; margin-bottom:1.4rem; }\n    .modal-remember input[type=&quot;checkbox&quot;] { accent-color:var(--gold); }\n    .modal-remember label { font-size:.75rem; color:rgba(255,255,255,0.4); }\n    .btn-modal-submit { width:100%; padding:.9rem; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; border-radius:10px; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.9rem; font-weight:700; cursor:pointer; transition:transform .3s,box-shadow .3s; letter-spacing:.03em; }\n    .btn-modal-submit:hover { transform:translateY(-2px); box-shadow:0 10px 28px rgba(201,168,76,0.4); }\n    .modal-error { background:rgba(248,113,113,.1); border:1px solid rgba(248,113,113,.3); border-radius:8px; padding:.75rem 1rem; color:#fca5a5; font-size:.8rem; margin-bottom:1.1rem; text-align:center; }\n\n    /* ── FLASH ── */\n    .flash { padding:1rem 5%; margin-top:72px; font-size:.875rem; }\n    .flash-success { background:rgba(74,222,128,.1); border-left:3px solid #4ade80; color:#166534; }\n    .flash-error   { background:rgba(248,113,113,.1); border-left:3px solid #f87171; color:#991b1b; }\n\n    /* ── HERO ── */\n    .hero { min-height:100vh; position:relative; display:flex; align-items:center; overflow:hidden; }\n    .hero-bg { position:absolute; inset:0; background:url(&#039;https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=1920&amp;q=80&#039;) center/cover no-repeat; }\n    .hero-overlay { position:absolute; inset:0; background:linear-gradient(135deg,rgba(13,27,42,0.95) 0%,rgba(13,27,42,0.65) 50%,rgba(13,27,42,0.4) 100%); }\n    .hero-content { position:relative; z-index:2; padding:0 5%; max-width:720px; }\n    .hero-badge { display:inline-flex; align-items:center; gap:.5rem; background:rgba(201,168,76,0.15); border:1px solid rgba(201,168,76,0.35); color:var(--gold); padding:.4rem 1rem; border-radius:50px; font-size:.75rem; font-weight:600; letter-spacing:1.5px; text-transform:uppercase; margin-bottom:1.5rem; }\n    .hero h1 { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(2.5rem,6vw,5rem); line-height:1.1; margin-bottom:1.5rem; color:var(--white); }\n    .hero h1 em { font-style:italic; color:var(--gold); }\n    .hero p { font-size:1.05rem; color:rgba(255,255,255,0.7); line-height:1.75; margin-bottom:2.5rem; max-width:500px; }\n    .hero-btns { display:flex; gap:1rem; flex-wrap:wrap; }\n    .hero-search { position:absolute; bottom:2.5rem; left:5%; right:5%; z-index:2; }\n    .search-box { background:rgba(13,27,42,0.92); border:1px solid rgba(201,168,76,0.25); border-radius:16px; padding:1.4rem 2rem; display:flex; gap:1rem; align-items:center; flex-wrap:wrap; backdrop-filter:blur(20px); }\n    .search-field { flex:1; min-width:140px; display:flex; flex-direction:column; gap:.25rem; }\n    .search-field label { font-size:.65rem; text-transform:uppercase; letter-spacing:1.2px; color:var(--gold); font-weight:700; }\n    .search-field input, .search-field select { background:transparent; border:none; outline:none; color:var(--white); font-size:.9rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; cursor:pointer; }\n    .search-field select option { background:var(--navy); }\n    .search-divider { width:1px; height:36px; background:rgba(201,168,76,0.2); }\n    .search-btn { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.85rem 1.6rem; border-radius:10px; font-weight:700; font-size:.875rem; display:flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; white-space:nowrap; }\n    .search-btn:hover { transform:translateY(-2px); box-shadow:0 8px 25px rgba(201,168,76,0.4); }\n\n    /* ── BUTTONS ── */\n    .btn-primary { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); padding:.85rem 2rem; border-radius:50px; font-weight:700; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-primary:hover { transform:translateY(-3px); box-shadow:0 12px 35px rgba(201,168,76,0.4); }\n    .btn-outline-light { border:1px solid rgba(255,255,255,0.35); color:var(--white); padding:.85rem 2rem; border-radius:50px; font-weight:500; font-size:.9rem; text-decoration:none; display:inline-flex; align-items:center; gap:.5rem; backdrop-filter:blur(10px); transition:border-color .3s,background .3s; cursor:pointer; }\n    .btn-outline-light:hover { border-color:var(--gold); background:rgba(201,168,76,0.1); color:var(--gold); }\n    .btn-gold { background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.6rem 1.4rem; border-radius:50px; font-weight:700; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:transform .3s,box-shadow .3s; }\n    .btn-gold:hover { transform:translateY(-2px); box-shadow:0 8px 20px rgba(201,168,76,0.4); }\n    .btn-navy { background:var(--navy); color:var(--gold); border:1px solid rgba(201,168,76,0.3); padding:.6rem 1.4rem; border-radius:50px; font-weight:600; font-size:.85rem; text-decoration:none; display:inline-flex; align-items:center; gap:.4rem; transition:all .3s; }\n    .btn-navy:hover { background:var(--gold); color:var(--navy); }\n    .btn-danger-sm { background:rgba(220,38,38,0.1); color:#dc2626; border:1px solid rgba(220,38,38,0.2); padding:.4rem .9rem; border-radius:8px; cursor:pointer; font-size:.78rem; font-weight:600; text-decoration:none; display:inline-flex; align-items:center; gap:.3rem; transition:all .3s; }\n    .btn-danger-sm:hover { background:rgba(220,38,38,0.2); }\n\n    /* ── SECTIONS ── */\n    section { padding:5rem 5%; }\n    .section-label { display:inline-block; color:var(--gold); font-size:.72rem; font-weight:700; letter-spacing:2.5px; text-transform:uppercase; margin-bottom:.75rem; }\n    .section-title { font-family:&#039;Playfair Display&#039;,serif; font-size:clamp(1.8rem,3.5vw,2.8rem); color:var(--navy); line-height:1.2; margin-bottom:.75rem; }\n    .section-title.light { color:var(--white); }\n    .section-sub { color:var(--muted); font-size:.95rem; line-height:1.75; max-width:480px; }\n    .section-header { display:flex; justify-content:space-between; align-items:flex-end; margin-bottom:2.5rem; flex-wrap:wrap; gap:1rem; }\n\n    /* ── DESTINATIONS GRID ── */\n    #destinations { background:var(--cream); }\n    .dest-grid { display:grid; grid-template-columns:repeat(3,1fr); grid-template-rows:auto auto; gap:1.2rem; }\n    .dest-card { position:relative; border-radius:14px; overflow:hidden; cursor:pointer; }\n    .dest-card-featured { grid-row:1/3; }\n    .dest-card img { width:100%; height:100%; min-height:220px; object-fit:cover; transition:transform .6s; }\n    .dest-card-featured img { min-height:480px; }\n    .dest-card:hover img { transform:scale(1.07); }\n    .dest-overlay { position:absolute; inset:0; background:linear-gradient(to top,rgba(13,27,42,0.92) 0%,transparent 55%); display:flex; flex-direction:column; justify-content:flex-end; padding:1.6rem; }\n    .dest-badge { background:rgba(201,168,76,0.92); color:var(--navy); font-size:.65rem; font-weight:700; padding:.2rem .6rem; border-radius:50px; display:inline-block; margin-bottom:.6rem; width:fit-content; letter-spacing:.5px; text-transform:uppercase; }\n    .dest-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.3rem; color:var(--white); margin-bottom:.25rem; }\n    .dest-card-featured .dest-name { font-size:1.7rem; }\n    .dest-info { display:flex; justify-content:space-between; align-items:center; }\n    .dest-price { color:var(--gold); font-weight:700; font-size:.95rem; }\n    .dest-action { width:34px; height:34px; background:var(--gold); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--navy); font-size:.75rem; opacity:0; transform:translateY(8px); transition:opacity .3s,transform .3s; text-decoration:none; }\n    .dest-card:hover .dest-action { opacity:1; transform:translateY(0); }\n\n    /* ── PACKAGES ── */\n    #packages { background:var(--navy); }\n    .packages-grid { display:grid; grid-template-columns:repeat(3,1fr); gap:1.4rem; margin-top:2.5rem; }\n    .pkg-card { background:var(--navy-2); border:1px solid rgba(201,168,76,0.12); border-radius:14px; overflow:hidden; transition:transform .3s,box-shadow .3s,border-color .3s; position:relative; }\n    .pkg-card:hover { transform:translateY(-8px); box-shadow:0 25px 60px rgba(0,0,0,0.4); border-color:rgba(201,168,76,0.35); }\n    .pkg-card.featured { border-color:var(--gold); }\n    .pkg-ribbon { position:absolute; top:1rem; right:1rem; background:var(--gold); color:var(--navy); font-size:.65rem; font-weight:700; padding:.25rem .75rem; border-radius:50px; z-index:1; letter-spacing:.5px; }\n    .pkg-img { height:190px; overflow:hidden; }\n    .pkg-img img { width:100%; height:100%; object-fit:cover; transition:transform .5s; }\n    .pkg-card:hover .pkg-img img { transform:scale(1.08); }\n    .pkg-body { padding:1.4rem; }\n    .pkg-meta { display:flex; gap:.8rem; font-size:.75rem; color:rgba(255,255,255,0.5); margin-bottom:.9rem; flex-wrap:wrap; }\n    .pkg-meta span { display:flex; align-items:center; gap:.3rem; }\n    .pkg-meta i { color:var(--gold); }\n    .pkg-name { font-family:&#039;Playfair Display&#039;,serif; font-size:1.15rem; color:var(--white); margin-bottom:.4rem; }\n    .pkg-desc { color:rgba(255,255,255,0.55); font-size:.82rem; line-height:1.65; margin-bottom:1.1rem; }\n    .pkg-features { list-style:none; margin-bottom:1.3rem; }\n    .pkg-features li { font-size:.8rem; color:rgba(255,255,255,0.6); display:flex; align-items:center; gap:.45rem; padding:.25rem 0; }\n    .pkg-features i { color:var(--gold); font-size:.65rem; }\n    .pkg-footer { display:flex; justify-content:space-between; align-items:center; border-top:1px solid rgba(201,168,76,0.12); padding-top:1.1rem; }\n    .pkg-price-label { font-size:.7rem; color:rgba(255,255,255,0.45); }\n    .pkg-price { font-size:1.4rem; font-weight:700; color:var(--gold); }\n    .pkg-price small { font-size:.7rem; color:rgba(255,255,255,0.45); }\n\n    /* ── ABOUT ── */\n    #about { background:var(--cream); display:grid; grid-template-columns:1fr 1fr; gap:5rem; align-items:center; }\n    .about-img-wrap { position:relative; }\n    .about-img-main { width:100%; height:480px; object-fit:cover; border-radius:16px; }\n    .about-img-badge { position:absolute; bottom:-1.5rem; right:-1.5rem; background:var(--gold); color:var(--navy); border-radius:14px; padding:1.4rem; text-align:center; box-shadow:0 20px 50px rgba(201,168,76,0.3); }\n    .about-img-badge strong { font-size:2.2rem; display:block; line-height:1; font-family:&#039;Playfair Display&#039;,serif; }\n    .about-img-badge span { font-size:.75rem; font-weight:600; letter-spacing:.5px; }\n    .about-features { display:grid; grid-template-columns:1fr 1fr; gap:1rem; margin:1.8rem 0; }\n    .about-feat { display:flex; gap:.9rem; align-items:flex-start; background:var(--white); border:1px solid rgba(201,168,76,0.12); padding:1.1rem; border-radius:12px; transition:border-color .3s,box-shadow .3s; }\n    .about-feat:hover { border-color:var(--gold); box-shadow:var(--shadow); }\n    .about-feat-icon { width:40px; height:40px; background:rgba(201,168,76,0.1); border-radius:10px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .about-feat h4 { font-size:.875rem; color:var(--navy); margin-bottom:.25rem; font-weight:600; }\n    .about-feat p { font-size:.78rem; color:var(--muted); line-height:1.5; }\n\n    /* ── CONTACT ── */\n    #contact { background:var(--navy); display:grid; grid-template-columns:1fr 1.5fr; gap:5rem; align-items:start; }\n    .contact-items { display:flex; flex-direction:column; gap:1.4rem; margin-top:2rem; }\n    .contact-item { display:flex; gap:1rem; align-items:flex-start; }\n    .contact-icon { width:46px; height:46px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:12px; display:flex; align-items:center; justify-content:center; color:var(--gold); flex-shrink:0; }\n    .contact-item h4 { font-size:.78rem; color:rgba(255,255,255,0.5); margin-bottom:.2rem; text-transform:uppercase; letter-spacing:.5px; }\n    .contact-item p { color:var(--white); font-size:.9rem; }\n    .contact-form { background:rgba(255,255,255,0.04); border:1px solid rgba(201,168,76,0.15); border-radius:18px; padding:2.2rem; }\n    .contact-form h3 { font-family:&#039;Playfair Display&#039;,serif; margin-bottom:1.4rem; color:var(--white); font-size:1.3rem; }\n    .form-row { display:grid; grid-template-columns:1fr 1fr; gap:1rem; }\n    .form-group { margin-bottom:1.1rem; }\n    .form-group label { display:block; font-size:.72rem; color:rgba(255,255,255,0.55); font-weight:600; letter-spacing:.5px; text-transform:uppercase; margin-bottom:.45rem; }\n    .form-group input, .form-group select, .form-group textarea { width:100%; background:rgba(255,255,255,0.06); border:1px solid rgba(201,168,76,0.15); border-radius:10px; padding:.75rem 1rem; color:var(--white); font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.875rem; outline:none; transition:border-color .3s; }\n    .form-group input:focus, .form-group select:focus, .form-group textarea:focus { border-color:var(--gold); }\n    .form-group textarea { resize:vertical; min-height:100px; }\n    .form-group select option { background:var(--navy); }\n    .btn-submit { width:100%; background:linear-gradient(135deg,var(--gold),var(--gold-l)); color:var(--navy); border:none; cursor:pointer; padding:.95rem; border-radius:10px; font-weight:700; font-size:.95rem; font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; display:flex; align-items:center; justify-content:center; gap:.5rem; transition:transform .3s,box-shadow .3s; }\n    .btn-submit:hover { transform:translateY(-2px); box-shadow:0 12px 30px rgba(201,168,76,0.4); }\n\n    /* ── FOOTER ── */\n    footer { background:#07101a; border-top:1px solid rgba(201,168,76,0.1); padding:3.5rem 5% 2rem; }\n    .footer-grid { display:grid; grid-template-columns:1.5fr 1fr 1fr 1fr; gap:3rem; margin-bottom:2.5rem; }\n    .footer-brand p { color:rgba(255,255,255,0.45); font-size:.82rem; line-height:1.7; margin:1rem 0 1.3rem; }\n    .social-links { display:flex; gap:.7rem; }\n    .social-link { width:36px; height:36px; background:rgba(201,168,76,0.1); border:1px solid rgba(201,168,76,0.2); border-radius:50%; display:flex; align-items:center; justify-content:center; color:var(--gold); font-size:.8rem; text-decoration:none; transition:background .3s,transform .3s; }\n    .social-link:hover { background:var(--gold); color:var(--navy); transform:translateY(-3px); }\n    .footer-col h4 { font-size:.82rem; font-weight:700; color:var(--white); margin-bottom:1rem; letter-spacing:.5px; text-transform:uppercase; }\n    .footer-col ul { list-style:none; }\n    .footer-col ul li { margin-bottom:.55rem; }\n    .footer-col ul a { color:rgba(255,255,255,0.45); text-decoration:none; font-size:.82rem; transition:color .3s; display:flex; align-items:center; gap:.35rem; }\n    .footer-col ul a:hover { color:var(--gold); }\n    .footer-bottom { border-top:1px solid rgba(201,168,76,0.1); padding-top:1.4rem; display:flex; justify-content:space-between; align-items:center; flex-wrap:wrap; gap:1rem; }\n    .footer-bottom p { color:rgba(255,255,255,0.35); font-size:.78rem; }\n    .footer-bottom span { color:var(--gold); }\n\n    /* ── RESPONSIVE ── */\n    @media(max-width:1024px) {\n      .dest-grid { grid-template-columns:1fr 1fr; }\n      .dest-card-featured { grid-row:auto; }\n      .packages-grid { grid-template-columns:1fr 1fr; }\n      #about,#contact { grid-template-columns:1fr; gap:3rem; }\n      .footer-grid { grid-template-columns:1fr 1fr; }\n    }\n    @media(max-width:768px) {\n      .nav-links { display:none; }\n      .dest-grid,.packages-grid { grid-template-columns:1fr; }\n      .search-box { flex-direction:column; }\n      .search-divider { display:none; }\n      .about-features,.form-row { grid-template-columns:1fr; }\n      .footer-grid { grid-template-columns:1fr; gap:2rem; }\n      .about-img-badge { right:1rem; bottom:1rem; }\n      #chat-widget { bottom:16px !important; right:16px !important; }\n      #chat-popup  { width:calc(100vw - 32px) !important; }\n    }\n\n    @keyframes fadeInUp { from{opacity:0;transform:translateY(28px)} to{opacity:1;transform:translateY(0)} }\n    .fade-in  { animation:fadeInUp .8s ease forwards; }\n    .delay-1  { animation-delay:.2s; opacity:0; }\n    .delay-2  { animation-delay:.4s; opacity:0; }\n\n    {% block extra_css %}{% endblock %}\n  &lt;/style&gt;\n  {% block stylesheets %}{% endblock %}\n&lt;/head&gt;\n&lt;body&gt;\n\n{# ══ MODAL LOGIN ══════════════════════════════════════════════════ #}\n{% if not app.user %}\n&lt;div class=&quot;modal-overlay&quot; id=&quot;loginModal&quot;&gt;\n  &lt;div class=&quot;modal-card&quot;&gt;\n    &lt;button class=&quot;modal-close&quot; onclick=&quot;closeModal()&quot; title=&quot;Fermer&quot;&gt;✕&lt;/button&gt;\n    &lt;div class=&quot;modal-logo&quot;&gt;\n      &lt;h2&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/h2&gt;\n      &lt;p&gt;{{ &#039;login.title&#039;|trans }}&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;div style=&quot;display:flex; gap:.5rem; margin-bottom:1.5rem;&quot;&gt;\n      &lt;button onclick=&quot;switchTab(&#039;password&#039;)&quot; id=&quot;tab-password&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:700;\n               background:linear-gradient(135deg,var(--gold),var(--gold-l));\n               color:var(--navy); border:1px solid var(--gold); transition:all .3s;&quot;&gt;\n        🔑 {{ &#039;login.password_tab&#039;|trans }}\n      &lt;/button&gt;\n      &lt;button onclick=&quot;switchTab(&#039;faceid&#039;)&quot; id=&quot;tab-faceid&quot;\n        style=&quot;flex:1; padding:.6rem; border-radius:8px; cursor:pointer;\n               font-family:&#039;Plus Jakarta Sans&#039;,sans-serif; font-size:.82rem; font-weight:600;\n               background:transparent; color:rgba(255,255,255,0.6);\n               border:1px solid rgba(201,168,76,0.3); transition:all .3s;&quot;&gt;\n        📷 {{ &#039;login.faceid_tab&#039;|trans }}\n      &lt;/button&gt;\n    &lt;/div&gt;\n    {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n      &lt;div class=&quot;modal-error&quot;&gt;❌ {{ error.messageKey|trans(error.messageData, &#039;security&#039;) }}&lt;/div&gt;\n    {% endif %}\n    &lt;div id=&quot;panel-password&quot;&gt;\n      &lt;form method=&quot;POST&quot; action=&quot;{{ path(&#039;app_login&#039;) }}&quot;&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_email&quot;&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;email&quot; id=&quot;modal_email&quot; name=&quot;email&quot; value=&quot;{{ last_username ?? &#039;&#039; }}&quot; placeholder=&quot;votre@email.com&quot; autocomplete=&quot;email&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-field&quot;&gt;\n          &lt;label for=&quot;modal_password&quot;&gt;{{ &#039;login.password&#039;|trans }}&lt;/label&gt;\n          &lt;input type=&quot;password&quot; id=&quot;modal_password&quot; name=&quot;password&quot; placeholder=&quot;••••••••&quot; autocomplete=&quot;current-password&quot; required&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;modal-remember&quot;&gt;\n          &lt;input type=&quot;checkbox&quot; id=&quot;modal_remember&quot; name=&quot;_remember_me&quot;&gt;\n          &lt;label for=&quot;modal_remember&quot;&gt;{{ &#039;login.remember&#039;|trans }}&lt;/label&gt;\n        &lt;/div&gt;\n        &lt;input type=&quot;hidden&quot; name=&quot;_csrf_token&quot; value=&quot;{{ csrf_token(&#039;authenticate&#039;) }}&quot;&gt;\n        &lt;button type=&quot;submit&quot; class=&quot;btn-modal-submit&quot;&gt;\n          &lt;i class=&quot;fas fa-sign-in-alt&quot;&gt;&lt;/i&gt; {{ &#039;login.submit&#039;|trans }}\n        &lt;/button&gt;\n      &lt;/form&gt;\n    &lt;/div&gt;\n    &lt;div id=&quot;panel-faceid&quot; style=&quot;display:none;&quot;&gt;\n      &lt;div class=&quot;modal-field&quot;&gt;\n        &lt;label&gt;{{ &#039;login.email&#039;|trans }}&lt;/label&gt;\n        &lt;input type=&quot;email&quot; id=&quot;faceEmail&quot; placeholder=&quot;votre@email.com&quot; style=&quot;width:100%;padding:.8rem 1rem;background:rgba(255,255,255,0.06);border:1px solid rgba(201,168,76,0.2);border-radius:10px;color:var(--white);font-family:&#039;Plus Jakarta Sans&#039;,sans-serif;font-size:.875rem;outline:none;&quot;&gt;\n      &lt;/div&gt;\n      &lt;div style=&quot;position:relative;border-radius:12px;overflow:hidden;border:1px solid rgba(201,168,76,0.3);margin-bottom:1rem;background:#000;&quot;&gt;\n        &lt;video id=&quot;webcam&quot; autoplay playsinline style=&quot;width:100%;height:200px;display:block;object-fit:cover;&quot;&gt;&lt;/video&gt;\n        &lt;canvas id=&quot;canvas&quot; width=&quot;320&quot; height=&quot;240&quot; style=&quot;display:none;&quot;&gt;&lt;/canvas&gt;\n        &lt;div style=&quot;position:absolute;inset:0;display:flex;align-items:center;justify-content:center;pointer-events:none;&quot;&gt;\n          &lt;div style=&quot;width:110px;height:135px;border:2px solid var(--gold);border-radius:55px;opacity:.7;box-shadow:0 0 20px rgba(201,168,76,0.3);&quot;&gt;&lt;/div&gt;\n        &lt;/div&gt;\n        &lt;div style=&quot;position:absolute;bottom:.5rem;left:0;right:0;text-align:center;font-size:.7rem;color:rgba(255,255,255,0.5);&quot;&gt;\n          {{ &#039;login.face_center&#039;|trans }}\n        &lt;/div&gt;\n      &lt;/div&gt;\n      &lt;button id=&quot;faceLoginBtn&quot; class=&quot;btn-modal-submit&quot; type=&quot;button&quot;&gt;\n        &lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; {{ &#039;login.face_scan&#039;|trans }}\n      &lt;/button&gt;\n      &lt;p id=&quot;faceResult&quot; style=&quot;text-align:center;margin-top:.75rem;font-size:.82rem;min-height:1.2rem;color:rgba(255,255,255,0.6);&quot;&gt;&lt;/p&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n&lt;/div&gt;\n{% endif %}\n\n{# ══ NAVBAR ══════════════════════════════════════════════════════ #}\n&lt;nav id=&quot;navbar&quot;&gt;\n  &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot;&gt;Smart&lt;span&gt;Trip&lt;/span&gt;&lt;/a&gt;\n  &lt;ul class=&quot;nav-links&quot;&gt;\n    {% if is_granted(&#039;ROLE_ADMIN&#039;) %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot; style=&quot;color:var(--gold) !important;&quot;&gt;&lt;i class=&quot;fas fa-plus&quot;&gt;&lt;/i&gt; {{ &#039;nav.add&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% else %}\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;{{ &#039;nav.destinations&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;{{ &#039;nav.voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    {% endif %}\n    &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;{{ &#039;nav.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n    &lt;li&gt;\n      &lt;a href=&quot;#&quot; class=&quot;nav-cta&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n        &lt;i class=&quot;fas fa-paper-plane&quot;&gt;&lt;/i&gt; {{ &#039;nav.plan&#039;|trans }}\n      &lt;/a&gt;\n    &lt;/li&gt;\n\n    {# ── LANGUAGE SWITCHER ── #}\n    &lt;li&gt;\n      &lt;div class=&quot;lang-switcher&quot;&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;fr&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;fr&#039; %}active{% endif %}&quot;&gt;\n          🇫🇷 FR\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;en&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;en&#039; %}active{% endif %}&quot;&gt;\n          🇬🇧 EN\n        &lt;/a&gt;\n        &lt;span class=&quot;lang-divider&quot;&gt;|&lt;/span&gt;\n        &lt;a href=&quot;{{ path(&#039;change_locale&#039;, {locale: &#039;ar&#039;}) }}&quot;\n           class=&quot;lang-btn {% if app.request.locale == &#039;ar&#039; %}active{% endif %}&quot;&gt;\n          🇹🇳 AR\n        &lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/li&gt;\n\n    {# ── LOGIN / USER ── #}\n    &lt;li&gt;\n      {% if app.user %}\n        &lt;div style=&quot;display:flex;align-items:center;gap:.6rem;&quot;&gt;\n          &lt;span class=&quot;nav-user&quot;&gt;\n            &lt;i class=&quot;fas fa-user-circle&quot;&gt;&lt;/i&gt;\n            {{ app.user.email }}\n          &lt;/span&gt;\n          &lt;a href=&quot;{{ path(&#039;app_logout&#039;) }}&quot; class=&quot;btn-login-nav&quot; title=&quot;{{ &#039;nav.logout&#039;|trans }}&quot;&gt;\n            &lt;i class=&quot;fas fa-sign-out-alt&quot;&gt;&lt;/i&gt; {{ &#039;nav.logout&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/div&gt;\n      {% else %}\n        &lt;button class=&quot;btn-login-nav&quot; onclick=&quot;openModal()&quot; type=&quot;button&quot;&gt;\n          &lt;i class=&quot;fas fa-user&quot;&gt;&lt;/i&gt; {{ &#039;nav.login&#039;|trans }}\n        &lt;/button&gt;\n      {% endif %}\n    &lt;/li&gt;\n  &lt;/ul&gt;\n&lt;/nav&gt;\n\n{# ── FLASH MESSAGES ── #}\n{% for msg in app.flashes(&#039;success&#039;) %}\n  &lt;div class=&quot;flash flash-success&quot;&gt;✅ {{ msg }}&lt;/div&gt;\n{% endfor %}\n{% for msg in app.flashes(&#039;error&#039;) %}\n  &lt;div class=&quot;flash flash-error&quot;&gt;❌ {{ msg }}&lt;/div&gt;\n{% endfor %}\n\n{% block body %}{% endblock %}\n\n{# ══ FOOTER ══════════════════════════════════════════════════════ #}\n&lt;footer&gt;\n  &lt;div class=&quot;footer-grid&quot;&gt;\n    &lt;div class=&quot;footer-brand&quot;&gt;\n      &lt;a href=&quot;{{ path(&#039;app_home&#039;) }}&quot; class=&quot;nav-logo&quot; style=&quot;font-size:1.3rem&quot;&gt;Smart&lt;span style=&quot;color:#fff&quot;&gt;Trip&lt;/span&gt;&lt;/a&gt;\n      &lt;p&gt;{{ &#039;footer.desc&#039;|trans }}&lt;/p&gt;\n      &lt;div class=&quot;social-links&quot;&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-facebook-f&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-instagram&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-twitter&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n        &lt;a href=&quot;#&quot; class=&quot;social-link&quot;&gt;&lt;i class=&quot;fab fa-youtube&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.destinations&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.add_dest&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.voyages&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.all_voyages&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;admin_voyage_new&#039;) }}&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.create_voyage&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n    &lt;div class=&quot;footer-col&quot;&gt;\n      &lt;h4&gt;{{ &#039;footer.info&#039;|trans }}&lt;/h4&gt;\n      &lt;ul&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#about&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.about&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;&lt;a href=&quot;{{ path(&#039;app_home&#039;) }}#contact&quot;&gt;&lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.contact&#039;|trans }}&lt;/a&gt;&lt;/li&gt;\n        &lt;li&gt;\n          &lt;a href=&quot;#&quot; onclick=&quot;event.preventDefault();toggleSarahChat()&quot;&gt;\n            &lt;i class=&quot;fas fa-chevron-right&quot; style=&quot;font-size:.6rem&quot;&gt;&lt;/i&gt; {{ &#039;footer.sarah&#039;|trans }}\n          &lt;/a&gt;\n        &lt;/li&gt;\n      &lt;/ul&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;footer-bottom&quot;&gt;\n    &lt;p&gt;© 2025 &lt;span&gt;SmartTrip&lt;/span&gt;. {{ &#039;footer.rights&#039;|trans }}&lt;/p&gt;\n    &lt;p&gt;{{ &#039;footer.made_with&#039;|trans }} &lt;span&gt;♥&lt;/span&gt; {{ &#039;footer.for&#039;|trans }}&lt;/p&gt;\n  &lt;/div&gt;\n&lt;/footer&gt;\n\n{# ══ CHAT SARAH ══════════════════════════════════════════════════ #}\n{% include &#039;chat/_popup.html.twig&#039; %}\n\n{# ══ JAVASCRIPT ══════════════════════════════════════════════════ #}\n{% block javascripts %}\n&lt;script&gt;\n  window.addEventListener(&#039;scroll&#039;, () =&gt; {\n    const nav = document.getElementById(&#039;navbar&#039;);\n    if (!nav) return;\n    nav.style.background = window.scrollY &gt; 50 ? &#039;rgba(13,27,42,0.99)&#039; : &#039;rgba(13,27,42,0.96)&#039;;\n  });\n\n  document.querySelectorAll(&#039;a[href^=&quot;#&quot;]&#039;).forEach(a =&gt; {\n    a.addEventListener(&#039;click&#039;, e =&gt; {\n      const href = a.getAttribute(&#039;href&#039;);\n      if (href === &#039;#&#039;) return;\n      const t = document.querySelector(href);\n      if (t) { e.preventDefault(); t.scrollIntoView({behavior:&#039;smooth&#039;}); }\n    });\n  });\n\n  function openModal() {\n    document.getElementById(&#039;loginModal&#039;).classList.add(&#039;open&#039;);\n    document.body.style.overflow = &#039;hidden&#039;;\n    setTimeout(() =&gt; document.getElementById(&#039;modal_email&#039;)?.focus(), 100);\n  }\n\n  function closeModal() {\n    document.getElementById(&#039;loginModal&#039;)?.classList.remove(&#039;open&#039;);\n    document.body.style.overflow = &#039;&#039;;\n    const video = document.getElementById(&#039;webcam&#039;);\n    if (video &amp;&amp; video.srcObject) {\n      video.srcObject.getTracks().forEach(t =&gt; t.stop());\n      video.srcObject = null;\n      cameraStarted = false;\n    }\n  }\n\n  document.getElementById(&#039;loginModal&#039;)?.addEventListener(&#039;click&#039;, function(e) {\n    if (e.target === this) closeModal();\n  });\n\n  document.addEventListener(&#039;keydown&#039;, e =&gt; { if (e.key === &#039;Escape&#039;) closeModal(); });\n\n  {% if app.request.attributes.get(&#039;_route&#039;) == &#039;app_login&#039; and error is defined and error %}\n    document.addEventListener(&#039;DOMContentLoaded&#039;, () =&gt; openModal());\n  {% endif %}\n\n  function switchTab(tab) {\n    const isPassword = tab === &#039;password&#039;;\n    document.getElementById(&#039;panel-password&#039;).style.display = isPassword ? &#039;block&#039; : &#039;none&#039;;\n    document.getElementById(&#039;panel-faceid&#039;).style.display   = isPassword ? &#039;none&#039;  : &#039;block&#039;;\n    const tabPwd  = document.getElementById(&#039;tab-password&#039;);\n    const tabFace = document.getElementById(&#039;tab-faceid&#039;);\n    if (isPassword) {\n      tabPwd.style.cssText  += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabFace.style.cssText += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n    } else {\n      tabFace.style.cssText += &#039;background:linear-gradient(135deg,var(--gold),var(--gold-l));color:var(--navy);border:1px solid var(--gold);font-weight:700;&#039;;\n      tabPwd.style.cssText  += &#039;background:transparent;color:rgba(255,255,255,0.6);border:1px solid rgba(201,168,76,0.3);font-weight:600;&#039;;\n      startCamera();\n    }\n  }\n\n  let cameraStarted = false;\n  function startCamera() {\n    if (cameraStarted) return;\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const result = document.getElementById(&#039;faceResult&#039;);\n    if (!video) return;\n    navigator.mediaDevices.getUserMedia({ video: true })\n      .then(stream =&gt; { video.srcObject = stream; cameraStarted = true; })\n      .catch(() =&gt; {\n        if (result) { result.textContent = &#039;❌ Caméra non accessible&#039;; result.style.color = &#039;#f87171&#039;; }\n      });\n  }\n\n  document.getElementById(&#039;faceLoginBtn&#039;)?.addEventListener(&#039;click&#039;, async () =&gt; {\n    const result = document.getElementById(&#039;faceResult&#039;);\n    const btn    = document.getElementById(&#039;faceLoginBtn&#039;);\n    const video  = document.getElementById(&#039;webcam&#039;);\n    const canvas = document.getElementById(&#039;canvas&#039;);\n    const ctx    = canvas.getContext(&#039;2d&#039;);\n    ctx.drawImage(video, 0, 0, 320, 240);\n    result.textContent = &#039;⏳ Identification en cours...&#039;;\n    result.style.color = &#039;rgba(255,255,255,0.6)&#039;;\n    btn.disabled = true;\n    const formData = new FormData();\n    formData.append(&#039;face_image&#039;, canvas.toDataURL(&#039;image/jpeg&#039;));\n    try {\n      const res  = await fetch(&#039;/face-login&#039;, { method: &#039;POST&#039;, body: formData });\n      const data = await res.json();\n      if (data.success) {\n        result.textContent = `✅ Bienvenue ! (${data.confidence}%)`;\n        result.style.color = &#039;#4ade80&#039;;\n        setTimeout(() =&gt; window.location.href = data.redirect, 1200);\n      } else {\n        result.textContent = `❌ ${data.error ?? &#039;Visage non reconnu&#039;} (${data.confidence ?? 0}%)`;\n        result.style.color = &#039;#f87171&#039;;\n        btn.disabled = false;\n        btn.innerHTML = &#039;&lt;i class=&quot;fas fa-camera&quot;&gt;&lt;/i&gt; Réessayer&#039;;\n      }\n    } catch (e) {\n      result.textContent = &#039;❌ Erreur réseau&#039;;\n      result.style.color = &#039;#f87171&#039;;\n      btn.disabled = false;\n    }\n  });\n&lt;/script&gt;\n{% endblock %}\n\n&lt;/body&gt;\n&lt;/html&gt;\r\n        </p>\r\n      </div>\r\n\r\n      <div style=\\\"margin-top:1.8rem;text-align:center;\\\">\r\n        <a href=\\\"mailto:bechirhadiden8@gmail.com\\\"\r\n           style=\\\"display:inline-block;padding:.8rem 2rem;\r\n                  background:linear-gradient(135deg,#c9a84c,#e8c97a);\r\n                  color:#0d1b2a;text-decoration:none;border-radius:8px;\r\n                  font-weight:700;font-size:.85rem;\\\">\r\n          ↩ Répondre à hadiden\r\n        </a>\r\n      </div>\r\n    </div>\r\n\r\n    <div style=\\\"padding:1.2rem 2.5rem;border-top:1px solid rgba(201,168,76,0.1);\r\n                text-align:center;font-size:.72rem;color:rgba(255,255,255,0.25);\\\">\r\n      SmartTrip · Avenue Habib Bourguiba, Tunis · contact@smarttrip.tn\r\n    </div>\r\n\r\n  </div>\r\n</body>\r\n</html>\\\";i:3;s:5:\\\"utf-8\\\";i:4;a:0:{}i:5;a:2:{i:0;O:37:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\\":2:{s:46:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\0headers\\\";a:4:{s:4:\\\"from\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:4:\\\"From\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Com