(52, 'O:36:\\\"Symfony\\\\Component\\\\Messenger\\\\Envelope\\\":2:{s:44:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Envelope\\0stamps\\\";a:1:{s:46:\\\"Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\\";a:1:{i:0;O:46:\\\"Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\\":1:{s:55:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\0busName\\\";s:21:\\\"messenger.bus.default\\\";}}}s:45:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Envelope\\0message\\\";O:51:\\\"Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\\":2:{s:60:\\\"\\0Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\0message\\\";O:28:\\\"Symfony\\\\Component\\\\Mime\\\\Email\\\":6:{i:0;N;i:1;N;i:2;s:2174:\\\"<!DOCTYPE html>\r\n<html>\r\n<body style=\\\"margin:0;padding:0;background:#f5f0e8;font-family:\\\'Segoe UI\\\',sans-serif;\\\">\r\n  <div style=\\\"max-width:580px;margin:2rem auto;background:#0d1b2a;border-radius:16px;overflow:hidden;\\\">\r\n\r\n    <div style=\\\"background:linear-gradient(135deg,#c9a84c,#e8c97a);padding:2.5rem;text-align:center;\\\">\r\n      <h1 style=\\\"margin:0;font-family:Georgia,serif;font-size:1.6rem;color:#0d1b2a;\\\">\r\n        SmartTrip\r\n      </h1>\r\n      <p style=\\\"margin:.3rem 0 0;font-size:.78rem;color:rgba(13,27,42,0.65);\\\">\r\n        Agence de voyage premium\r\n      </p>\r\n    </div>\r\n\r\n    <div style=\\\"padding:2.5rem;text-align:center;\\\">\r\n      <div style=\\\"font-size:3rem;margin-bottom:1rem;\\\">✅</div>\r\n      <h2 style=\\\"font-family:Georgia,serif;font-weight:300;color:#ffffff;\r\n                  font-size:1.5rem;margin:0 0 .8rem;\\\">\r\n        Merci, hadiden !\r\n      </h2>\r\n      <p style=\\\"color:rgba(255,255,255,0.55);font-size:.9rem;line-height:1.7;margin:0 0 2rem;\\\">\r\n        Votre demande a bien été reçue.<br>\r\n        Un de nos conseillers vous contactera <strong style=\\\"color:#c9a84c;\\\">sous 24h</strong>\r\n        pour construire votre voyage idéal.\r\n      </p>\r\n\r\n      <div style=\\\"background:rgba(201,168,76,0.08);border:1px solid rgba(201,168,76,0.2);\r\n                  border-radius:12px;padding:1.4rem;text-align:left;margin-bottom:2rem;\\\">\r\n        <p style=\\\"margin:0 0 .8rem;font-size:.72rem;text-transform:uppercase;\r\n                   letter-spacing:.12em;color:#c9a84c;font-weight:700;\\\">\r\n          Récapitulatif de votre demande\r\n        </p>\r\n        <p style=\\\"margin:.3rem 0;color:rgba(255,255,255,0.65);font-size:.84rem;\\\">\r\n          <strong style=\\\"color:#fff;\\\">Destination :</strong>\r\n          paris\r\n        </p>\r\n        <p style=\\\"margin:.3rem 0;color:rgba(255,255,255,0.65);font-size:.84rem;\\\">\r\n          <strong style=\\\"color:#fff;\\\">Budget :</strong>\r\n          12222222222\r\n        </p>\r\n      </div>\r\n\r\n      <div style=\\\"font-size:.78rem;color:rgba(255,255,255,0.25);line-height:1.6;\\\">\r\n        SmartTrip · +216 71 234 567<br>\r\n        contact@smarttrip.tn · Ave Habib Bourguiba, Tunis\r\n      </div>\r\n    </div>\r\n\r\n  </div>\r\n</body>\r\n</html>\\\";i:3;s:5:\\\"utf-8\\\";i:4;a:0:{}i:5;a:2:{i:0;O:37:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\\":2:{s:46:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\0headers\\\";a:3:{s:4:\\\"from\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:4:\\\"From\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:58:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\0addresses\\\";a:1:{i:0;O:30:\\\"Symfony\\\\Component\\\\Mime\\\\Address\\\":2:{s:39:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0address\\\";s:23:\\\"bechirhadidan@gmail.com\\\";s:36:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0name\\\";s:9:\\\"SmartTrip\\\";}}}}s:2:\\\"to\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:2:\\\"To\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:58:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\0addresses\\\";a:1:{i:0;O:30:\\\"Symfony\\\\Component\\\\Mime\\\\Address\\\":2:{s:39:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0address\\\";s:24:\\\"bechirhadiden8@gmail.com\\\";s:36:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0name\\\";s:14:\\\"hadiden bechir\\\";}}}}s:7:\\\"subject\\\";a:1:{i:0;O:48:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\UnstructuredHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:7:\\\"Subject\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:55:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\UnstructuredHeader\\0value\\\";s:51:\\\"✅ SmartTrip — Votre demande a bien été reçue\\\";}}}s:49:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\0lineLength\\\";i:76;}i:1;N;}}s:61:\\\"\\0Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\0envelope\\\";N;}}', '[]', 'default', '2026-04-23 10:30:29', '2026-04-23 10:30:29', NULL),
(53, 'O:36:\\\"Symfony\\\\Component\\\\Messenger\\\\Envelope\\\":2:{s:44:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Envelope\\0stamps\\\";a:1:{s:46:\\\"Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\\";a:1:{i:0;O:46:\\\"Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\\":1:{s:55:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Stamp\\\\BusNameStamp\\0busName\\\";s:21:\\\"messenger.bus.default\\\";}}}s:45:\\\"\\0Symfony\\\\Component\\\\Messenger\\\\Envelope\\0message\\\";O:51:\\\"Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\\":2:{s:60:\\\"\\0Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\0message\\\";O:28:\\\"Symfony\\\\Component\\\\Mime\\\\Email\\\":6:{i:0;N;i:1;N;i:2;s:37301:\\\"<!DOCTYPE html>\r\n<html>\r\n<body style=\\\"margin:0;padding:0;background:#f5f0e8;font-family:\\\'Segoe UI\\\',sans-serif;\\\">\r\n  <div style=\\\"max-width:580px;margin:2rem auto;background:#0d1b2a;border-radius:16px;overflow:hidden;\\\">\r\n\r\n    <div style=\\\"background:linear-gradient(135deg,#c9a84c,#e8c97a);padding:2rem 2.5rem;\\\">\r\n      <h1 style=\\\"margin:0;font-size:1.4rem;color:#0d1b2a;font-family:Georgia,serif;\\\">\r\n        📩 Nouvelle demande de devis\r\n      </h1>\r\n      <p style=\\\"margin:.4rem 0 0;font-size:.82rem;color:rgba(13,27,42,0.7);\\\">\r\n        Reçue le 23/04/2026 à 12:37\r\n      </p>\r\n    </div>\r\n\r\n    <div style=\\\"padding:2rem 2.5rem;\\\">\r\n      <table style=\\\"width:100%;border-collapse:collapse;\\\">\r\n        <tr>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.78rem;color:rgba(255,255,255,0.4);width:35%;vertical-align:top;\\\">\r\n    👤 Nom complet\r\n  </td>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.84rem;color:#fff;font-weight:500;\\\">\r\n    hadiden bechir\r\n  </td>\r\n</tr>\r\n        <tr>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.78rem;color:rgba(255,255,255,0.4);width:35%;vertical-align:top;\\\">\r\n    📧 Email\r\n  </td>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.84rem;color:#fff;font-weight:500;\\\">\r\n    bechirhadiden8@gmail.com\r\n  </td>\r\n</tr>\r\n        <tr>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.78rem;color:rgba(255,255,255,0.4);width:35%;vertical-align:top;\\\">\r\n    📞 Téléphone\r\n  </td>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.84rem;color:#fff;font-weight:500;\\\">\r\n    +21690117054\r\n  </td>\r\n</tr>\r\n        <tr>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.78rem;color:rgba(255,255,255,0.4);width:35%;vertical-align:top;\\\">\r\n    🌍 Destination\r\n  </td>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.84rem;color:#fff;font-weight:500;\\\">\r\n    paris\r\n  </td>\r\n</tr>\r\n        <tr>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.78rem;color:rgba(255,255,255,0.4);width:35%;vertical-align:top;\\\">\r\n    💰 Budget\r\n  </td>\r\n  <td style=\\\"padding:.55rem 0;border-bottom:1px solid rgba(201,168,76,0.08);\r\n             font-size:.84rem;color:#fff;font-weight:500;\\\">\r\n    12222222222\r\n  </td>\r\n</tr>\r\n      </table>\r\n\r\n      <div style=\\\"margin-top:1.5rem;padding:1.2rem 1.5rem;\r\n                  background:rgba(201,168,76,0.08);\r\n                  border-left:3px solid #c9a84c;border-radius:4px;\\\">\r\n        <p style=\\\"margin:0 0 .5rem;font-size:.72rem;text-transform:uppercase;\r\n                   letter-spacing:.1em;color:#c9a84c;font-weight:700;\\\">\r\n          Message\r\n        </p>\r\n        <p style=\\\"margin:0;color:rgba(255,255,255,0.8);font-size:.88rem;line-height:1.65;\\\">\r\n          v{% extends &#039;base_dark.html.twig&#039; %}\n{% block title %}Smart Trip – Agence de Voyage Premium{% endblock %}\n\n{% block body %}\n\n{# ── HERO ── #}\n&lt;section class=&quot;hero&quot;&gt;\n  &lt;div class=&quot;hero-bg&quot;&gt;&lt;/div&gt;\n  &lt;div class=&quot;hero-overlay&quot;&gt;&lt;/div&gt;\n  &lt;div class=&quot;hero-content fade-in&quot;&gt;\n    &lt;div class=&quot;hero-badge&quot;&gt;&lt;i class=&quot;fas fa-star&quot;&gt;&lt;/i&gt; Agence Premium depuis 2026&lt;/div&gt;\n    &lt;h1&gt;Explorez le Monde&lt;br&gt;avec &lt;em&gt;Élégance&lt;/em&gt;&lt;/h1&gt;\n    &lt;p&gt;Des voyages sur mesure, des expériences inoubliables. Laissez-nous vous emmener vers des destinations exceptionnelles soigneusement sélectionnées.&lt;/p&gt;\n    &lt;div class=&quot;hero-btns&quot;&gt;\n      &lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot; class=&quot;btn-primary delay-1&quot;&gt;&lt;i class=&quot;fas fa-compass&quot;&gt;&lt;/i&gt; Voir nos voyages&lt;/a&gt;\n      &lt;a href=&quot;#contact&quot; class=&quot;btn-outline-light delay-2&quot;&gt;&lt;i class=&quot;fas fa-phone&quot;&gt;&lt;/i&gt; Nous contacter&lt;/a&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n\n  &lt;div class=&quot;hero-search&quot;&gt;\n    &lt;form class=&quot;search-box&quot; action=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot; method=&quot;GET&quot;&gt;\n      &lt;div class=&quot;search-field&quot;&gt;\n        &lt;label&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; Destination&lt;/label&gt;\n        &lt;select name=&quot;q&quot;&gt;\n          &lt;option value=&quot;&quot;&gt;Toutes les destinations&lt;/option&gt;\n          {% for dest in destinations %}\n            &lt;option value=&quot;{{ dest.nom }}&quot;&gt;{{ dest.nom }}, {{ dest.pays }}&lt;/option&gt;\n          {% endfor %}\n        &lt;/select&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;search-divider&quot;&gt;&lt;/div&gt;\n      &lt;div class=&quot;search-field&quot;&gt;\n        &lt;label&gt;&lt;i class=&quot;fas fa-globe&quot;&gt;&lt;/i&gt; Pays&lt;/label&gt;\n        &lt;select name=&quot;pays&quot;&gt;\n          &lt;option value=&quot;&quot;&gt;Tous les pays&lt;/option&gt;\n          {% for dest in destinations %}\n            &lt;option value=&quot;{{ dest.pays }}&quot;&gt;{{ dest.pays }}&lt;/option&gt;\n          {% endfor %}\n        &lt;/select&gt;\n      &lt;/div&gt;\n      &lt;button class=&quot;search-btn&quot; type=&quot;submit&quot;&gt;\n        &lt;i class=&quot;fas fa-search&quot;&gt;&lt;/i&gt; Rechercher\n      &lt;/button&gt;\n    &lt;/form&gt;\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── DESTINATIONS ── #}\n&lt;section id=&quot;destinations&quot;&gt;\n  &lt;div class=&quot;section-header&quot;&gt;\n    &lt;div&gt;\n      &lt;span class=&quot;section-label&quot;&gt;Explorer&lt;/span&gt;\n      &lt;h2 class=&quot;section-title&quot;&gt;Destinations Populaires&lt;/h2&gt;\n      &lt;p class=&quot;section-sub&quot;&gt;Des endroits magiques sélectionnés par nos experts pour des voyages mémorables.&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot; class=&quot;btn-navy&quot;&gt;Voir tout &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;dest-grid&quot;&gt;\n    {% for dest in destinations %}\n      &lt;div class=&quot;dest-card {% if loop.first %}dest-card-featured{% endif %}&quot;&gt;\n        {% set img = dest.firstImage %}\n        &lt;img src=&quot;{{ img ?? &#039;https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600&amp;q=80&#039; }}&quot;\n             alt=&quot;{{ dest.nom }}&quot; loading=&quot;lazy&quot;&gt;\n        &lt;div class=&quot;dest-overlay&quot;&gt;\n          {% if loop.first %}\n            &lt;div class=&quot;dest-badge&quot;&gt;⭐ Coup de cœur&lt;/div&gt;\n          {% elseif dest.codeIata %}\n            &lt;div class=&quot;dest-badge&quot;&gt;{{ dest.codeIata }}&lt;/div&gt;\n          {% endif %}\n          &lt;div class=&quot;dest-name&quot;&gt;{{ dest.nom }}, {{ dest.pays }}&lt;/div&gt;\n          &lt;div class=&quot;dest-info&quot;&gt;\n            &lt;span style=&quot;color:rgba(255,255,255,0.65);font-size:.82rem;&quot;&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; {{ dest.pays }}&lt;/span&gt;\n            &lt;span class=&quot;dest-price&quot;&gt;\n              {% if dest.voyages|length &gt; 0 %}À partir de {{ dest.voyages|first.prix|number_format(0,&#039;,&#039;,&#039; &#039;) }} TND\n              {% else %}Sur devis{% endif %}\n            &lt;/span&gt;\n            &lt;a href=&quot;{{ path(&#039;client_destination_show&#039;, {id: dest.id}) }}&quot; class=&quot;dest-action&quot;&gt;&lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n          &lt;/div&gt;\n        &lt;/div&gt;\n      &lt;/div&gt;\n    {% else %}\n      &lt;div style=&quot;grid-column:1/-1;text-align:center;padding:3rem;color:var(--muted);&quot;&gt;\n        &lt;p&gt;Aucune destination disponible.&lt;/p&gt;\n        &lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot; class=&quot;btn-gold&quot; style=&quot;margin-top:1rem;&quot;&gt;+ Ajouter une destination&lt;/a&gt;\n      &lt;/div&gt;\n    {% endfor %}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── VOYAGES ── #}\n&lt;section id=&quot;packages&quot;&gt;\n  &lt;div class=&quot;section-header&quot;&gt;\n    &lt;div&gt;\n      &lt;span class=&quot;section-label&quot; style=&quot;color:var(--gold-l)&quot;&gt;Nos Formules&lt;/span&gt;\n      &lt;h2 class=&quot;section-title light&quot;&gt;Voyages &amp; Packages&lt;/h2&gt;\n      &lt;p class=&quot;section-sub&quot; style=&quot;color:rgba(255,255,255,0.55)&quot;&gt;Tout inclus pour voyager l&#039;esprit serein, du budget au luxe absolu.&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot; class=&quot;btn-gold&quot;&gt;Tous les voyages &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;packages-grid&quot;&gt;\n    {% for voyage in voyages %}\n      {% if voyage.imagePath %}\n        {% set pkgImg = voyage.imagePath %}\n      {% elseif voyage.destinationRel and voyage.destinationRel.firstImage %}\n        {% set pkgImg = voyage.destinationRel.firstImage %}\n      {% else %}\n        {% set pkgImg = &#039;https://images.unsplash.com/photo-1501179691627-eeaa65ea017c?w=600&amp;q=80&#039; %}\n      {% endif %}\n\n      &lt;div class=&quot;pkg-card {% if loop.first %}featured{% endif %}&quot;&gt;\n        {% if loop.first %}&lt;div class=&quot;pkg-ribbon&quot;&gt;⭐ Populaire&lt;/div&gt;{% endif %}\n        &lt;div class=&quot;pkg-img&quot;&gt;\n          &lt;img src=&quot;{{ pkgImg }}&quot; alt=&quot;{{ voyage.destination }}&quot; loading=&quot;lazy&quot;&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;pkg-body&quot;&gt;\n          &lt;div class=&quot;pkg-meta&quot;&gt;\n            &lt;span&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; {{ voyage.destination }}&lt;/span&gt;\n            &lt;span&gt;&lt;i class=&quot;fas fa-clock&quot;&gt;&lt;/i&gt; {{ voyage.dureeJours }} jours&lt;/span&gt;\n            {% if voyage.paysDepart %}\n              &lt;span&gt;&lt;i class=&quot;fas fa-plane-departure&quot;&gt;&lt;/i&gt; {{ voyage.paysDepart }}&lt;/span&gt;\n            {% endif %}\n          &lt;/div&gt;\n          &lt;div class=&quot;pkg-name&quot;&gt;{{ voyage.destination }}&lt;/div&gt;\n          {% if voyage.description %}\n            &lt;div class=&quot;pkg-desc&quot;&gt;{{ voyage.description|slice(0,100) }}{% if voyage.description|length &gt; 100 %}...{% endif %}&lt;/div&gt;\n          {% endif %}\n          &lt;ul class=&quot;pkg-features&quot;&gt;\n            &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; Du {{ voyage.dateDebut|date(&#039;d/m/Y&#039;) }} au {{ voyage.dateFin|date(&#039;d/m/Y&#039;) }}&lt;/li&gt;\n            &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; {{ voyage.dureeJours }} jours / {{ voyage.dureeJours - 1 }} nuits&lt;/li&gt;\n            {% if voyage.paysDepart %}\n              &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; Départ depuis {{ voyage.paysDepart }}&lt;/li&gt;\n            {% endif %}\n          &lt;/ul&gt;\n          &lt;div class=&quot;pkg-footer&quot;&gt;\n            &lt;div&gt;\n              &lt;div class=&quot;pkg-price-label&quot;&gt;À partir de&lt;/div&gt;\n              &lt;div class=&quot;pkg-price&quot;&gt;{{ voyage.prix|number_format(0,&#039;,&#039;,&#039; &#039;) }} &lt;small&gt;TND / pers.&lt;/small&gt;&lt;/div&gt;\n            &lt;/div&gt;\n            &lt;a href=&quot;{{ path(&#039;client_voyage_show&#039;, {id: voyage.id}) }}&quot; class=&quot;btn-gold&quot;&gt;Voir le voyage&lt;/a&gt;\n          &lt;/div&gt;\n        &lt;/div&gt;\n      &lt;/div&gt;\n    {% else %}\n      &lt;div style=&quot;grid-column:1/-1;text-align:center;padding:3rem;color:rgba(255,255,255,0.4);&quot;&gt;\n        &lt;p&gt;Aucun voyage disponible.&lt;/p&gt;\n        &lt;a href=&quot;{{ path(&#039;admin_voyage_new&#039;) }}&quot; class=&quot;btn-gold&quot; style=&quot;margin-top:1rem;&quot;&gt;+ Ajouter un voyage&lt;/a&gt;\n      &lt;/div&gt;\n    {% endfor %}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── À PROPOS ── #}\n&lt;section id=&quot;about&quot;&gt;\n  &lt;div class=&quot;about-img-wrap&quot;&gt;\n    &lt;img class=&quot;about-img-main&quot; src=&quot;https://images.unsplash.com/photo-1578894381163-e72c17f2d45f?w=700&amp;q=80&quot; alt=&quot;Notre équipe&quot;&gt;\n    &lt;div class=&quot;about-img-badge&quot;&gt;&lt;strong&gt;16&lt;/strong&gt;&lt;span&gt;ans d&#039;expertise&lt;/span&gt;&lt;/div&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;about-content&quot;&gt;\n    &lt;span class=&quot;section-label&quot;&gt;Notre histoire&lt;/span&gt;\n    &lt;h2 class=&quot;section-title&quot;&gt;Votre confiance,&lt;br&gt;notre passion&lt;/h2&gt;\n    &lt;p class=&quot;section-sub&quot; style=&quot;max-width:100%;margin-bottom:1.5rem;&quot;&gt;\n      Depuis 2008, notre agence accompagne des milliers de voyageurs dans la réalisation de leurs rêves.\n    &lt;/p&gt;\n    &lt;div class=&quot;about-features&quot;&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-shield-alt&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Voyages sécurisés&lt;/h4&gt;&lt;p&gt;Suivi en temps réel et assistance 24h/24 durant votre séjour.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-user-tie&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Conseillers experts&lt;/h4&gt;&lt;p&gt;Une équipe dédiée avec une connaissance terrain approfondie.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-tag&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Meilleur prix garanti&lt;/h4&gt;&lt;p&gt;Nous alignons tout concurrent sur le même séjour.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-sliders-h&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;100% sur mesure&lt;/h4&gt;&lt;p&gt;Chaque voyage est conçu selon vos envies et votre budget.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;#contact&quot; class=&quot;btn-primary&quot;&gt;Parler à un conseiller &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── CONTACT ── #}\n{# ── CONTACT ── #}\n&lt;section id=&quot;contact&quot;&gt;\n  &lt;div class=&quot;contact-info&quot;&gt;\n    &lt;span class=&quot;section-label&quot; style=&quot;color:var(--gold-l)&quot;&gt;Contactez-nous&lt;/span&gt;\n    &lt;h2 class=&quot;section-title light&quot;&gt;Planifions votre&lt;br&gt;voyage ensemble&lt;/h2&gt;\n    &lt;p class=&quot;section-sub&quot; style=&quot;color:rgba(255,255,255,0.55);margin-bottom:0;&quot;&gt;\n      Un conseiller dédié vous répond sous 24h pour construire votre voyage idéal.\n    &lt;/p&gt;\n    &lt;div class=&quot;contact-items&quot;&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-phone&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Téléphone&lt;/h4&gt;&lt;p&gt;+216 71 234 567&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-envelope&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Email&lt;/h4&gt;&lt;p&gt;contact@SmartTrip.tn&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Adresse&lt;/h4&gt;&lt;p&gt;Avenue Habib Bourguiba, Tunis&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-clock&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Horaires&lt;/h4&gt;&lt;p&gt;Lun–Sam : 8h00 – 18h00&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n\n  &lt;div class=&quot;contact-form&quot;&gt;\n    &lt;h3&gt;Demande de devis gratuit&lt;/h3&gt;\n\n    {% for msg in app.flashes(&#039;contact_success&#039;) %}\n      &lt;div style=&quot;background:rgba(74,222,128,0.15);border:1px solid rgba(74,222,128,0.4);\n                  border-radius:10px;padding:.9rem 1.2rem;margin-bottom:1.2rem;\n                  display:flex;align-items:center;gap:.6rem;&quot;&gt;\n        &lt;span style=&quot;font-size:1.1rem;&quot;&gt;✅&lt;/span&gt;\n        &lt;p style=&quot;color:#d1fae5;font-size:.875rem;margin:0;font-weight:500;&quot;&gt;{{ msg }}&lt;/p&gt;\n      &lt;/div&gt;\n    {% endfor %}\n\n    {% for msg in app.flashes(&#039;contact_error&#039;) %}\n      &lt;div style=&quot;background:rgba(239,68,68,0.15);border:1px solid rgba(239,68,68,0.35);\n                  border-radius:10px;padding:.9rem 1.2rem;margin-bottom:1.2rem;\n                  display:flex;align-items:center;gap:.6rem;&quot;&gt;\n        &lt;span style=&quot;font-size:1.1rem;&quot;&gt;❌&lt;/span&gt;\n        &lt;p style=&quot;color:#fecaca;font-size:.875rem;margin:0;font-weight:500;&quot;&gt;{{ msg }}&lt;/p&gt;\n      &lt;/div&gt;\n    {% endfor %}\n\n    {# ✅ action explicite vers app_home #}\n    {{ form_start(contactForm, {\n        action: path(&#039;app_home&#039;),\n        method: &#039;POST&#039;,\n        attr: {id: &#039;homeContactForm&#039;}\n    }) }}\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Prénom *&lt;/label&gt;\n        {{ form_widget(contactForm.prenom) }}\n        {{ form_errors(contactForm.prenom) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Nom *&lt;/label&gt;\n        {{ form_widget(contactForm.nom) }}\n        {{ form_errors(contactForm.nom) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Email *&lt;/label&gt;\n        {{ form_widget(contactForm.email) }}\n        {{ form_errors(contactForm.email) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Téléphone&lt;/label&gt;\n        {{ form_widget(contactForm.telephone) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Destination souhaitée&lt;/label&gt;\n        {{ form_widget(contactForm.destinationSouhaitee) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Budget estimé&lt;/label&gt;\n        {{ form_widget(contactForm.budget) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-group&quot;&gt;\n      &lt;label&gt;Votre message *&lt;/label&gt;\n      {{ form_widget(contactForm.message) }}\n      {{ form_errors(contactForm.message) }}\n    &lt;/div&gt;\n\n    {# ✅ onclick retiré — il bloquait la soumission si erreur JS #}\n    &lt;button type=&quot;submit&quot; class=&quot;btn-submit&quot; id=&quot;homeSubmitBtn&quot;&gt;\n      &lt;i class=&quot;fas fa-paper-plane&quot;&gt;&lt;/i&gt; Envoyer ma demande\n    &lt;/button&gt;\n\n    {{ form_end(contactForm) }}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{% endblock %}\n{% extends &#039;base_dark.html.twig&#039; %}\n{% block title %}Smart Trip – Agence de Voyage Premium{% endblock %}\n\n{% block body %}\n\n{# ── HERO ── #}\n&lt;section class=&quot;hero&quot;&gt;\n  &lt;div class=&quot;hero-bg&quot;&gt;&lt;/div&gt;\n  &lt;div class=&quot;hero-overlay&quot;&gt;&lt;/div&gt;\n  &lt;div class=&quot;hero-content fade-in&quot;&gt;\n    &lt;div class=&quot;hero-badge&quot;&gt;&lt;i class=&quot;fas fa-star&quot;&gt;&lt;/i&gt; Agence Premium depuis 2026&lt;/div&gt;\n    &lt;h1&gt;Explorez le Monde&lt;br&gt;avec &lt;em&gt;Élégance&lt;/em&gt;&lt;/h1&gt;\n    &lt;p&gt;Des voyages sur mesure, des expériences inoubliables. Laissez-nous vous emmener vers des destinations exceptionnelles soigneusement sélectionnées.&lt;/p&gt;\n    &lt;div class=&quot;hero-btns&quot;&gt;\n      &lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot; class=&quot;btn-primary delay-1&quot;&gt;&lt;i class=&quot;fas fa-compass&quot;&gt;&lt;/i&gt; Voir nos voyages&lt;/a&gt;\n      &lt;a href=&quot;#contact&quot; class=&quot;btn-outline-light delay-2&quot;&gt;&lt;i class=&quot;fas fa-phone&quot;&gt;&lt;/i&gt; Nous contacter&lt;/a&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n\n  &lt;div class=&quot;hero-search&quot;&gt;\n    &lt;form class=&quot;search-box&quot; action=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot; method=&quot;GET&quot;&gt;\n      &lt;div class=&quot;search-field&quot;&gt;\n        &lt;label&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; Destination&lt;/label&gt;\n        &lt;select name=&quot;q&quot;&gt;\n          &lt;option value=&quot;&quot;&gt;Toutes les destinations&lt;/option&gt;\n          {% for dest in destinations %}\n            &lt;option value=&quot;{{ dest.nom }}&quot;&gt;{{ dest.nom }}, {{ dest.pays }}&lt;/option&gt;\n          {% endfor %}\n        &lt;/select&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;search-divider&quot;&gt;&lt;/div&gt;\n      &lt;div class=&quot;search-field&quot;&gt;\n        &lt;label&gt;&lt;i class=&quot;fas fa-globe&quot;&gt;&lt;/i&gt; Pays&lt;/label&gt;\n        &lt;select name=&quot;pays&quot;&gt;\n          &lt;option value=&quot;&quot;&gt;Tous les pays&lt;/option&gt;\n          {% for dest in destinations %}\n            &lt;option value=&quot;{{ dest.pays }}&quot;&gt;{{ dest.pays }}&lt;/option&gt;\n          {% endfor %}\n        &lt;/select&gt;\n      &lt;/div&gt;\n      &lt;button class=&quot;search-btn&quot; type=&quot;submit&quot;&gt;\n        &lt;i class=&quot;fas fa-search&quot;&gt;&lt;/i&gt; Rechercher\n      &lt;/button&gt;\n    &lt;/form&gt;\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── DESTINATIONS ── #}\n&lt;section id=&quot;destinations&quot;&gt;\n  &lt;div class=&quot;section-header&quot;&gt;\n    &lt;div&gt;\n      &lt;span class=&quot;section-label&quot;&gt;Explorer&lt;/span&gt;\n      &lt;h2 class=&quot;section-title&quot;&gt;Destinations Populaires&lt;/h2&gt;\n      &lt;p class=&quot;section-sub&quot;&gt;Des endroits magiques sélectionnés par nos experts pour des voyages mémorables.&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;{{ path(&#039;client_destination_index&#039;) }}&quot; class=&quot;btn-navy&quot;&gt;Voir tout &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;dest-grid&quot;&gt;\n    {% for dest in destinations %}\n      &lt;div class=&quot;dest-card {% if loop.first %}dest-card-featured{% endif %}&quot;&gt;\n        {% set img = dest.firstImage %}\n        &lt;img src=&quot;{{ img ?? &#039;https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600&amp;q=80&#039; }}&quot;\n             alt=&quot;{{ dest.nom }}&quot; loading=&quot;lazy&quot;&gt;\n        &lt;div class=&quot;dest-overlay&quot;&gt;\n          {% if loop.first %}\n            &lt;div class=&quot;dest-badge&quot;&gt;⭐ Coup de cœur&lt;/div&gt;\n          {% elseif dest.codeIata %}\n            &lt;div class=&quot;dest-badge&quot;&gt;{{ dest.codeIata }}&lt;/div&gt;\n          {% endif %}\n          &lt;div class=&quot;dest-name&quot;&gt;{{ dest.nom }}, {{ dest.pays }}&lt;/div&gt;\n          &lt;div class=&quot;dest-info&quot;&gt;\n            &lt;span style=&quot;color:rgba(255,255,255,0.65);font-size:.82rem;&quot;&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; {{ dest.pays }}&lt;/span&gt;\n            &lt;span class=&quot;dest-price&quot;&gt;\n              {% if dest.voyages|length &gt; 0 %}À partir de {{ dest.voyages|first.prix|number_format(0,&#039;,&#039;,&#039; &#039;) }} TND\n              {% else %}Sur devis{% endif %}\n            &lt;/span&gt;\n            &lt;a href=&quot;{{ path(&#039;client_destination_show&#039;, {id: dest.id}) }}&quot; class=&quot;dest-action&quot;&gt;&lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n          &lt;/div&gt;\n        &lt;/div&gt;\n      &lt;/div&gt;\n    {% else %}\n      &lt;div style=&quot;grid-column:1/-1;text-align:center;padding:3rem;color:var(--muted);&quot;&gt;\n        &lt;p&gt;Aucune destination disponible.&lt;/p&gt;\n        &lt;a href=&quot;{{ path(&#039;admin_destination_new&#039;) }}&quot; class=&quot;btn-gold&quot; style=&quot;margin-top:1rem;&quot;&gt;+ Ajouter une destination&lt;/a&gt;\n      &lt;/div&gt;\n    {% endfor %}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── VOYAGES ── #}\n&lt;section id=&quot;packages&quot;&gt;\n  &lt;div class=&quot;section-header&quot;&gt;\n    &lt;div&gt;\n      &lt;span class=&quot;section-label&quot; style=&quot;color:var(--gold-l)&quot;&gt;Nos Formules&lt;/span&gt;\n      &lt;h2 class=&quot;section-title light&quot;&gt;Voyages &amp; Packages&lt;/h2&gt;\n      &lt;p class=&quot;section-sub&quot; style=&quot;color:rgba(255,255,255,0.55)&quot;&gt;Tout inclus pour voyager l&#039;esprit serein, du budget au luxe absolu.&lt;/p&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;{{ path(&#039;client_voyage_index&#039;) }}&quot; class=&quot;btn-gold&quot;&gt;Tous les voyages &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;packages-grid&quot;&gt;\n    {% for voyage in voyages %}\n      {% if voyage.imagePath %}\n        {% set pkgImg = voyage.imagePath %}\n      {% elseif voyage.destinationRel and voyage.destinationRel.firstImage %}\n        {% set pkgImg = voyage.destinationRel.firstImage %}\n      {% else %}\n        {% set pkgImg = &#039;https://images.unsplash.com/photo-1501179691627-eeaa65ea017c?w=600&amp;q=80&#039; %}\n      {% endif %}\n\n      &lt;div class=&quot;pkg-card {% if loop.first %}featured{% endif %}&quot;&gt;\n        {% if loop.first %}&lt;div class=&quot;pkg-ribbon&quot;&gt;⭐ Populaire&lt;/div&gt;{% endif %}\n        &lt;div class=&quot;pkg-img&quot;&gt;\n          &lt;img src=&quot;{{ pkgImg }}&quot; alt=&quot;{{ voyage.destination }}&quot; loading=&quot;lazy&quot;&gt;\n        &lt;/div&gt;\n        &lt;div class=&quot;pkg-body&quot;&gt;\n          &lt;div class=&quot;pkg-meta&quot;&gt;\n            &lt;span&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt; {{ voyage.destination }}&lt;/span&gt;\n            &lt;span&gt;&lt;i class=&quot;fas fa-clock&quot;&gt;&lt;/i&gt; {{ voyage.dureeJours }} jours&lt;/span&gt;\n            {% if voyage.paysDepart %}\n              &lt;span&gt;&lt;i class=&quot;fas fa-plane-departure&quot;&gt;&lt;/i&gt; {{ voyage.paysDepart }}&lt;/span&gt;\n            {% endif %}\n          &lt;/div&gt;\n          &lt;div class=&quot;pkg-name&quot;&gt;{{ voyage.destination }}&lt;/div&gt;\n          {% if voyage.description %}\n            &lt;div class=&quot;pkg-desc&quot;&gt;{{ voyage.description|slice(0,100) }}{% if voyage.description|length &gt; 100 %}...{% endif %}&lt;/div&gt;\n          {% endif %}\n          &lt;ul class=&quot;pkg-features&quot;&gt;\n            &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; Du {{ voyage.dateDebut|date(&#039;d/m/Y&#039;) }} au {{ voyage.dateFin|date(&#039;d/m/Y&#039;) }}&lt;/li&gt;\n            &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; {{ voyage.dureeJours }} jours / {{ voyage.dureeJours - 1 }} nuits&lt;/li&gt;\n            {% if voyage.paysDepart %}\n              &lt;li&gt;&lt;i class=&quot;fas fa-check-circle&quot;&gt;&lt;/i&gt; Départ depuis {{ voyage.paysDepart }}&lt;/li&gt;\n            {% endif %}\n          &lt;/ul&gt;\n          &lt;div class=&quot;pkg-footer&quot;&gt;\n            &lt;div&gt;\n              &lt;div class=&quot;pkg-price-label&quot;&gt;À partir de&lt;/div&gt;\n              &lt;div class=&quot;pkg-price&quot;&gt;{{ voyage.prix|number_format(0,&#039;,&#039;,&#039; &#039;) }} &lt;small&gt;TND / pers.&lt;/small&gt;&lt;/div&gt;\n            &lt;/div&gt;\n            &lt;a href=&quot;{{ path(&#039;client_voyage_show&#039;, {id: voyage.id}) }}&quot; class=&quot;btn-gold&quot;&gt;Voir le voyage&lt;/a&gt;\n          &lt;/div&gt;\n        &lt;/div&gt;\n      &lt;/div&gt;\n    {% else %}\n      &lt;div style=&quot;grid-column:1/-1;text-align:center;padding:3rem;color:rgba(255,255,255,0.4);&quot;&gt;\n        &lt;p&gt;Aucun voyage disponible.&lt;/p&gt;\n        &lt;a href=&quot;{{ path(&#039;admin_voyage_new&#039;) }}&quot; class=&quot;btn-gold&quot; style=&quot;margin-top:1rem;&quot;&gt;+ Ajouter un voyage&lt;/a&gt;\n      &lt;/div&gt;\n    {% endfor %}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── À PROPOS ── #}\n&lt;section id=&quot;about&quot;&gt;\n  &lt;div class=&quot;about-img-wrap&quot;&gt;\n    &lt;img class=&quot;about-img-main&quot; src=&quot;https://images.unsplash.com/photo-1578894381163-e72c17f2d45f?w=700&amp;q=80&quot; alt=&quot;Notre équipe&quot;&gt;\n    &lt;div class=&quot;about-img-badge&quot;&gt;&lt;strong&gt;16&lt;/strong&gt;&lt;span&gt;ans d&#039;expertise&lt;/span&gt;&lt;/div&gt;\n  &lt;/div&gt;\n  &lt;div class=&quot;about-content&quot;&gt;\n    &lt;span class=&quot;section-label&quot;&gt;Notre histoire&lt;/span&gt;\n    &lt;h2 class=&quot;section-title&quot;&gt;Votre confiance,&lt;br&gt;notre passion&lt;/h2&gt;\n    &lt;p class=&quot;section-sub&quot; style=&quot;max-width:100%;margin-bottom:1.5rem;&quot;&gt;\n      Depuis 2008, notre agence accompagne des milliers de voyageurs dans la réalisation de leurs rêves.\n    &lt;/p&gt;\n    &lt;div class=&quot;about-features&quot;&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-shield-alt&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Voyages sécurisés&lt;/h4&gt;&lt;p&gt;Suivi en temps réel et assistance 24h/24 durant votre séjour.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-user-tie&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Conseillers experts&lt;/h4&gt;&lt;p&gt;Une équipe dédiée avec une connaissance terrain approfondie.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-tag&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Meilleur prix garanti&lt;/h4&gt;&lt;p&gt;Nous alignons tout concurrent sur le même séjour.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;about-feat&quot;&gt;\n        &lt;div class=&quot;about-feat-icon&quot;&gt;&lt;i class=&quot;fas fa-sliders-h&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;100% sur mesure&lt;/h4&gt;&lt;p&gt;Chaque voyage est conçu selon vos envies et votre budget.&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n    &lt;a href=&quot;#contact&quot; class=&quot;btn-primary&quot;&gt;Parler à un conseiller &lt;i class=&quot;fas fa-arrow-right&quot;&gt;&lt;/i&gt;&lt;/a&gt;\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{# ── CONTACT ── #}\n{# ── CONTACT ── #}\n&lt;section id=&quot;contact&quot;&gt;\n  &lt;div class=&quot;contact-info&quot;&gt;\n    &lt;span class=&quot;section-label&quot; style=&quot;color:var(--gold-l)&quot;&gt;Contactez-nous&lt;/span&gt;\n    &lt;h2 class=&quot;section-title light&quot;&gt;Planifions votre&lt;br&gt;voyage ensemble&lt;/h2&gt;\n    &lt;p class=&quot;section-sub&quot; style=&quot;color:rgba(255,255,255,0.55);margin-bottom:0;&quot;&gt;\n      Un conseiller dédié vous répond sous 24h pour construire votre voyage idéal.\n    &lt;/p&gt;\n    &lt;div class=&quot;contact-items&quot;&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-phone&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Téléphone&lt;/h4&gt;&lt;p&gt;+216 71 234 567&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-envelope&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Email&lt;/h4&gt;&lt;p&gt;contact@SmartTrip.tn&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-map-marker-alt&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Adresse&lt;/h4&gt;&lt;p&gt;Avenue Habib Bourguiba, Tunis&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n      &lt;div class=&quot;contact-item&quot;&gt;\n        &lt;div class=&quot;contact-icon&quot;&gt;&lt;i class=&quot;fas fa-clock&quot;&gt;&lt;/i&gt;&lt;/div&gt;\n        &lt;div&gt;&lt;h4&gt;Horaires&lt;/h4&gt;&lt;p&gt;Lun–Sam : 8h00 – 18h00&lt;/p&gt;&lt;/div&gt;\n      &lt;/div&gt;\n    &lt;/div&gt;\n  &lt;/div&gt;\n\n  &lt;div class=&quot;contact-form&quot;&gt;\n    &lt;h3&gt;Demande de devis gratuit&lt;/h3&gt;\n\n    {% for msg in app.flashes(&#039;contact_success&#039;) %}\n      &lt;div style=&quot;background:rgba(74,222,128,0.15);border:1px solid rgba(74,222,128,0.4);\n                  border-radius:10px;padding:.9rem 1.2rem;margin-bottom:1.2rem;\n                  display:flex;align-items:center;gap:.6rem;&quot;&gt;\n        &lt;span style=&quot;font-size:1.1rem;&quot;&gt;✅&lt;/span&gt;\n        &lt;p style=&quot;color:#d1fae5;font-size:.875rem;margin:0;font-weight:500;&quot;&gt;{{ msg }}&lt;/p&gt;\n      &lt;/div&gt;\n    {% endfor %}\n\n    {% for msg in app.flashes(&#039;contact_error&#039;) %}\n      &lt;div style=&quot;background:rgba(239,68,68,0.15);border:1px solid rgba(239,68,68,0.35);\n                  border-radius:10px;padding:.9rem 1.2rem;margin-bottom:1.2rem;\n                  display:flex;align-items:center;gap:.6rem;&quot;&gt;\n        &lt;span style=&quot;font-size:1.1rem;&quot;&gt;❌&lt;/span&gt;\n        &lt;p style=&quot;color:#fecaca;font-size:.875rem;margin:0;font-weight:500;&quot;&gt;{{ msg }}&lt;/p&gt;\n      &lt;/div&gt;\n    {% endfor %}\n\n    {# ✅ action explicite vers app_home #}\n    {{ form_start(contactForm, {\n        action: path(&#039;app_home&#039;),\n        method: &#039;POST&#039;,\n        attr: {id: &#039;homeContactForm&#039;}\n    }) }}\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Prénom *&lt;/label&gt;\n        {{ form_widget(contactForm.prenom) }}\n        {{ form_errors(contactForm.prenom) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Nom *&lt;/label&gt;\n        {{ form_widget(contactForm.nom) }}\n        {{ form_errors(contactForm.nom) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Email *&lt;/label&gt;\n        {{ form_widget(contactForm.email) }}\n        {{ form_errors(contactForm.email) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Téléphone&lt;/label&gt;\n        {{ form_widget(contactForm.telephone) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-row&quot;&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Destination souhaitée&lt;/label&gt;\n        {{ form_widget(contactForm.destinationSouhaitee) }}\n      &lt;/div&gt;\n      &lt;div class=&quot;form-group&quot;&gt;\n        &lt;label&gt;Budget estimé&lt;/label&gt;\n        {{ form_widget(contactForm.budget) }}\n      &lt;/div&gt;\n    &lt;/div&gt;\n\n    &lt;div class=&quot;form-group&quot;&gt;\n      &lt;label&gt;Votre message *&lt;/label&gt;\n      {{ form_widget(contactForm.message) }}\n      {{ form_errors(contactForm.message) }}\n    &lt;/div&gt;\n\n    {# ✅ onclick retiré — il bloquait la soumission si erreur JS #}\n    &lt;button type=&quot;submit&quot; class=&quot;btn-submit&quot; id=&quot;homeSubmitBtn&quot;&gt;\n      &lt;i class=&quot;fas fa-paper-plane&quot;&gt;&lt;/i&gt; Envoyer ma demande\n    &lt;/button&gt;\n\n    {{ form_end(contactForm) }}\n  &lt;/div&gt;\n&lt;/section&gt;\n\n{% endblock %}\r\n        </p>\r\n      </div>\r\n\r\n      <div style=\\\"margin-top:1.8rem;text-align:center;\\\">\r\n        <a href=\\\"mailto:bechirhadiden8@gmail.com\\\"\r\n           style=\\\"display:inline-block;padding:.8rem 2rem;\r\n                  background:linear-gradient(135deg,#c9a84c,#e8c97a);\r\n                  color:#0d1b2a;text-decoration:none;border-radius:8px;\r\n                  font-weight:700;font-size:.85rem;\\\">\r\n          ↩ Répondre à hadiden\r\n        </a>\r\n      </div>\r\n    </div>\r\n\r\n    <div style=\\\"padding:1.2rem 2.5rem;border-top:1px solid rgba(201,168,76,0.1);\r\n                text-align:center;font-size:.72rem;color:rgba(255,255,255,0.25);\\\">\r\n      SmartTrip · Avenue Habib Bourguiba, Tunis · contact@smarttrip.tn\r\n    </div>\r\n\r\n  </div>\r\n</body>\r\n</html>\\\";i:3;s:5:\\\"utf-8\\\";i:4;a:0:{}i:5;a:2:{i:0;O:37:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\\":2:{s:46:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\0headers\\\";a:4:{s:4:\\\"from\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:4:\\\"From\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:58:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\0addresses\\\";a:1:{i:0;O:30:\\\"Symfony\\\\Component\\\\Mime\\\\Address\\\":2:{s:39:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0address\\\";s:23:\\\"bechirhadidan@gmail.com\\\";s:36:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0name\\\";s:9:\\\"SmartTrip\\\";}}}}s:2:\\\"to\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:2:\\\"To\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:58:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\0addresses\\\";a:1:{i:0;O:30:\\\"Symfony\\\\Component\\\\Mime\\\\Address\\\":2:{s:39:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0address\\\";s:23:\\\"bechirhadidan@gmail.com\\\";s:36:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0name\\\";s:0:\\\"\\\";}}}}s:8:\\\"reply-to\\\";a:1:{i:0;O:47:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:8:\\\"Reply-To\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:58:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\MailboxListHeader\\0addresses\\\";a:1:{i:0;O:30:\\\"Symfony\\\\Component\\\\Mime\\\\Address\\\":2:{s:39:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0address\\\";s:24:\\\"bechirhadiden8@gmail.com\\\";s:36:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Address\\0name\\\";s:14:\\\"hadiden bechir\\\";}}}}s:7:\\\"subject\\\";a:1:{i:0;O:48:\\\"Symfony\\\\Component\\\\Mime\\\\Header\\\\UnstructuredHeader\\\":5:{s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0name\\\";s:7:\\\"Subject\\\";s:56:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lineLength\\\";i:76;s:50:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0lang\\\";N;s:53:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\AbstractHeader\\0charset\\\";s:5:\\\"utf-8\\\";s:55:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\UnstructuredHeader\\0value\\\";s:40:\\\"📩 Nouvelle demande — hadiden bechir\\\";}}}s:49:\\\"\\0Symfony\\\\Component\\\\Mime\\\\Header\\\\Headers\\0lineLength\\\";i:76;}i:1;N;}}s:61:\\\"\\0Symfony\\\\Component\\\\Mailer\\\\Messenger\\\\SendEmailMessage\\0envelope\\\";N;}}', '[]', 'default', '2026-04-23 10:37:25', '2026-04-23 10:37:25', NULL);
INSERT INTO `messenger_messages` (`id`, `body`, `headers`, `queue_name`, `created_at`, `available_at`, `delivered_at`) VALUES
